@router.post("/demonstration-learner/demonstrations/{demonstration_id}/steps")
async def demonstration_learner_add_step(demonstration_id: str, request: Request):
    """Append a trajectory step to an existing demonstration."""
    try:
        from sparkai.agent.agent_demonstration_learner import get_demonstration_learner
        body = await request.json()
        engine = get_demonstration_learner()
        step = engine.add_trajectory_step(
            demonstration_id=demonstration_id,
            state=body.get("state", {}),
            action=body.get("action", {}),
            reward=float(body.get("reward", 0.0)),
            next_state=body.get("next_state", {}),
            done=bool(body.get("done", False)),
            metadata=body.get("metadata"),
        )
        if step is None:
            return JSONResponse({"status": "error", "message": "Demonstration not found"}, status_code=404)
        return JSONResponse({"status": "success", "data": step.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


@router.post("/demonstration-learner/demonstrations/{demonstration_id}/finalize")
async def demonstration_learner_finalize(demonstration_id: str, request: Request):
    """Mark a demonstration as FINALIZED and immutable."""
    try:
        from sparkai.agent.agent_demonstration_learner import (
            get_demonstration_learner, TrajectoryQuality,
        )
        body = await request.json()
        quality = None
        quality_str = body.get("quality")
        if quality_str is not None:
            try:
                quality = TrajectoryQuality(quality_str)
            except ValueError:
                return JSONResponse({"status": "error", "message": "Invalid quality"}, status_code=400)
        engine = get_demonstration_learner()
        demo = engine.finalize_demonstration(demonstration_id, quality)
        if demo is None:
            return JSONResponse({"status": "error", "message": "Demonstration not found"}, status_code=404)
        return JSONResponse({"status": "success", "data": demo.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


