@router.post("/leaderboard-system/leaderboards")
async def leaderboard_system_create_leaderboard(request: Request):
    """Create a new leaderboard definition."""
    try:
        from sparkai.engine.engine_leaderboard_system import (
            get_leaderboard_system, ScoreType, SortOrder, LeaderboardScope,
        )
        engine = get_leaderboard_system()
        body = await request.json()
        try:
            score_type = ScoreType(body.get("score_type", "score"))
            sort_order = SortOrder(body.get("sort_order", "descending"))
            scope = LeaderboardScope(body.get("scope", "global"))
        except ValueError as e:
            return JSONResponse({"status": "error", "message": str(e)}, status_code=400)
        leaderboard = engine.create_leaderboard(
            name=body.get("name", ""),
            description=body.get("description", ""),
            score_type=score_type,
            sort_order=sort_order,
            scope=scope,
            max_entries=int(body.get("max_entries", 1000)),
            metadata=body.get("metadata"),
        )
        return JSONResponse({"status": "success", "data": leaderboard.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


