@router.post("/accessibility-system/presets")
async def accessibility_system_create_preset(request: Request):
    """Create a reusable accessibility preset."""
    try:
        from sparkai.engine.engine_accessibility_system import (
            get_accessibility_system, ColorblindMode, ContrastMode, MotionReduction,
            SubtitleBackground, SubtitleConfig, TextScalingConfig, AudioDescription,
        )
        engine = get_accessibility_system()
        body = await request.json()
        try:
            colorblind_mode = ColorblindMode(body.get("colorblind_mode", "none"))
            contrast_mode = ContrastMode(body.get("contrast_mode", "normal"))
            motion_reduction = MotionReduction(body.get("motion_reduction", "none"))
        except ValueError as e:
            return JSONResponse({"status": "error", "message": str(e)}, status_code=400)

        ts_body = body.get("text_scaling", {}) or {}
        text_scaling = TextScalingConfig(
            ui_scale=float(ts_body.get("ui_scale", 1.0)),
            subtitle_scale=float(ts_body.get("subtitle_scale", 1.0)),
            hud_scale=float(ts_body.get("hud_scale", 1.0)),
            tooltip_scale=float(ts_body.get("tooltip_scale", 1.0)),
            min_scale=float(ts_body.get("min_scale", 0.5)),
            max_scale=float(ts_body.get("max_scale", 3.0)),
        )

        sub_body = body.get("subtitle_config", {}) or {}
        try:
            sub_background = SubtitleBackground(sub_body.get("background", "solid"))
        except ValueError as e:
            return JSONResponse({"status": "error", "message": str(e)}, status_code=400)
        subtitle_config = SubtitleConfig(
            enabled=bool(sub_body.get("enabled", True)),
            font_size=float(sub_body.get("font_size", 18.0)),
            background=sub_background,
            text_color=sub_body.get("text_color", "#ffffff"),
            background_color=sub_body.get("background_color", "#000000"),
            position_y=float(sub_body.get("position_y", 0.15)),
            duration_multiplier=float(sub_body.get("duration_multiplier", 1.0)),
            speaker_label=bool(sub_body.get("speaker_label", True)),
            sound_cue_labels=bool(sub_body.get("sound_cue_labels", False)),
        )

        ad_body = body.get("audio_description", {}) or {}
        audio_description = AudioDescription(
            enabled=bool(ad_body.get("enabled", False)),
            volume=float(ad_body.get("volume", 0.8)),
            narration_speed=float(ad_body.get("narration_speed", 1.0)),
            describe_environment=bool(ad_body.get("describe_environment", False)),
            describe_actions=bool(ad_body.get("describe_actions", False)),
            describe_menu=bool(ad_body.get("describe_menu", False)),
        )

        preset = engine.create_preset(
            name=body.get("name", ""),
            description=body.get("description", ""),
            colorblind_mode=colorblind_mode,
            contrast_mode=contrast_mode,
            motion_reduction=motion_reduction,
            text_scaling=text_scaling,
            subtitle_config=subtitle_config,
            audio_description=audio_description,
        )
        return JSONResponse({"status": "success", "data": preset.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


