@router.post("/creativity-engine/ideas")
async def creativity_engine_generate_idea(request: Request):
    """Generate a new creative idea."""
    try:
        from sparkai.agent.agent_creativity_engine import (
            get_creativity_engine, CreativeDomain, ThinkingMode,
        )
        engine = get_creativity_engine()
        body = await request.json()
        try:
            domain = CreativeDomain(body.get("domain", "mechanic"))
            thinking_mode = ThinkingMode(body.get("thinking_mode", "divergent"))
        except ValueError as e:
            return JSONResponse({"status": "error", "message": str(e)}, status_code=400)
        idea = engine.generate_idea(
            title=body.get("title", ""),
            description=body.get("description", ""),
            domain=domain,
            thinking_mode=thinking_mode,
            agent_id=body.get("agent_id", ""),
            tags=body.get("tags", []),
            source_inspirations=body.get("source_inspirations", []),
            metadata=body.get("metadata", {}),
        )
        return JSONResponse({"status": "success", "data": idea.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


@router.get("/creativity-engine/ideas")
async def creativity_engine_list_ideas(
    domain: Optional[str] = None,
    status: Optional[str] = None,
    thinking_mode: Optional[str] = None,
    agent_id: Optional[str] = None,
    min_novelty: Optional[float] = None,
):
    """List creative ideas, optionally filtered."""
    try:
        from sparkai.agent.agent_creativity_engine import (
            get_creativity_engine, CreativeDomain, ThinkingMode, IdeaStatus,
        )
        engine = get_creativity_engine()
        dom = None
        if domain:
            try:
                dom = CreativeDomain(domain)
            except ValueError:
                return JSONResponse({"status": "error", "message": f"Invalid domain: {domain}"}, status_code=400)
        st = None
        if status:
            try:
                st = IdeaStatus(status)
            except ValueError:
                return JSONResponse({"status": "error", "message": f"Invalid status: {status}"}, status_code=400)
        tm = None
        if thinking_mode:
            try:
                tm = ThinkingMode(thinking_mode)
            except ValueError:
                return JSONResponse({"status": "error", "message": f"Invalid thinking_mode: {thinking_mode}"}, status_code=400)
        ideas = engine.list_ideas(
            domain=dom, status=st, thinking_mode=tm,
            agent_id=agent_id, min_novelty=min_novelty,
        )
        return JSONResponse({"status": "success", "data": [i.to_dict() for i in ideas]})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


