@router.post("/creativity-engine/ideas/combine")
async def creativity_engine_combine_ideas(request: Request):
    """Create a new idea by fusing two or more existing source ideas."""
    try:
        from sparkai.agent.agent_creativity_engine import (
            get_creativity_engine, CreativeDomain, ThinkingMode,
        )
        engine = get_creativity_engine()
        body = await request.json()
        try:
            domain = CreativeDomain(body.get("domain", "mechanic"))
            thinking_mode = ThinkingMode(body.get("thinking_mode", "combinatorial"))
        except ValueError as e:
            return JSONResponse({"status": "error", "message": str(e)}, status_code=400)
        result_idea, combination = engine.combine_ideas(
            source_idea_ids=body.get("source_idea_ids", []),
            title=body.get("title", ""),
            description=body.get("description", ""),
            domain=domain,
            thinking_mode=thinking_mode,
            agent_id=body.get("agent_id", ""),
            combination_strategy=body.get("combination_strategy", ""),
        )
        return JSONResponse({"status": "success", "data": {
            "idea": result_idea.to_dict(),
            "combination": combination.to_dict(),
        }})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


