@router.post("/hud-system/widgets")
async def hud_system_create_widget(request: Request):
    """Create a new HUD widget."""
    try:
        from sparkai.engine.engine_hud_system import (
            get_hud_system, WidgetType, WidgetAnchor
        )
        body = await request.json()
        try:
            widget_type = WidgetType(body.get("widget_type"))
        except ValueError:
            return JSONResponse({"status": "error", "message": "Invalid widget_type"}, status_code=400)
        try:
            anchor = WidgetAnchor(body.get("anchor"))
        except ValueError:
            return JSONResponse({"status": "error", "message": "Invalid anchor"}, status_code=400)
        engine = get_hud_system()
        widget = engine.create_widget(
            widget_type=widget_type,
            player_id=body.get("player_id", ""),
            anchor=anchor,
            offset_x=body.get("offset_x", 0.0),
            offset_y=body.get("offset_y", 0.0),
            width=body.get("width", 100.0),
            height=body.get("height", 30.0),
            current_value=body.get("current_value", 100.0),
            max_value=body.get("max_value", 100.0),
            display_text=body.get("display_text", ""),
            color=body.get("color", "#FFFFFF"),
            icon=body.get("icon", ""),
            visible=body.get("visible", True),
            opacity=body.get("opacity", 1.0),
            metadata=body.get("metadata"),
        )
        return JSONResponse({"status": "success", "data": widget.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


