@router.post("/status-effect-system/effects")
async def status_effect_system_register_effect(request: Request):
    """Register a new status effect template."""
    try:
        from sparkai.engine.engine_status_effect_system import (
            get_status_effect_system, EffectCategory, EffectElement,
            StackingPolicy, DispelType, EffectSeverity,
        )
        body = await request.json()
        try:
            category = EffectCategory(body.get("category", "debuff"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": f"Invalid category"}, status_code=400
            )
        try:
            element = EffectElement(body.get("element", "physical"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": f"Invalid element"}, status_code=400
            )
        try:
            severity = EffectSeverity(body.get("severity", "moderate"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": f"Invalid severity"}, status_code=400
            )
        try:
            stacking_policy = StackingPolicy(body.get("stacking_policy", "no_stack"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": f"Invalid stacking_policy"}, status_code=400
            )
        try:
            dispel_type = DispelType(body.get("dispel_type", "magic"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": f"Invalid dispel_type"}, status_code=400
            )
        engine = get_status_effect_system()
        definition = engine.register_effect(
            name=body.get("name", ""),
            description=body.get("description", ""),
            category=category,
            element=element,
            severity=severity,
            stacking_policy=stacking_policy,
            dispel_type=dispel_type,
            base_duration=float(body.get("base_duration", 0.0)),
            tick_interval=float(body.get("tick_interval", 1.0)),
            base_intensity=float(body.get("base_intensity", 1.0)),
            stat_modifiers=body.get("stat_modifiers"),
            damage_per_tick=float(body.get("damage_per_tick", 0.0)),
            heal_per_tick=float(body.get("heal_per_tick", 0.0)),
            dispellable=bool(body.get("dispellable", True)),
            chain_effect_id=body.get("chain_effect_id"),
            icon=body.get("icon", ""),
            color=body.get("color", ""),
            tags=body.get("tags"),
            metadata=body.get("metadata"),
        )
        return JSONResponse({"status": "success", "data": definition.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


