@router.post("/status-effect-system/resistance-profiles")
async def status_effect_system_create_resistance_profile(request: Request):
    """Create (or replace) a resistance profile for an entity."""
    try:
        from sparkai.engine.engine_status_effect_system import (
            get_status_effect_system, EffectElement,
        )
        body = await request.json()
        entity_id = body.get("entity_id", "")
        resistances_raw = body.get("resistances", {}) or {}
        immunities_raw = body.get("immunities", []) or []
        susceptibility_raw = body.get("susceptibility", {}) or {}

        resistances = {}
        for key, value in resistances_raw.items():
            try:
                resistances[EffectElement(key)] = float(value)
            except ValueError:
                return JSONResponse(
                    {"status": "error", "message": f"Invalid resistance element: {key}"},
                    status_code=400,
                )

        immunities = []
        for item in immunities_raw:
            try:
                immunities.append(EffectElement(item))
            except ValueError:
                return JSONResponse(
                    {"status": "error", "message": f"Invalid immunity element: {item}"},
                    status_code=400,
                )

        susceptibility = {}
        for key, value in susceptibility_raw.items():
            try:
                susceptibility[EffectElement(key)] = float(value)
            except ValueError:
                return JSONResponse(
                    {"status": "error", "message": f"Invalid susceptibility element: {key}"},
                    status_code=400,
                )

        engine = get_status_effect_system()
        profile = engine.create_resistance_profile(
            entity_id=entity_id,
            resistances=resistances,
            immunities=immunities,
            susceptibility=susceptibility,
        )
        return JSONResponse({"status": "success", "data": profile.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


