@router.post("/status-effect-system/apply")
async def status_effect_system_apply_effect(request: Request):
    """Apply a status effect to an entity with immunity and resistance resolution."""
    try:
        from sparkai.engine.engine_status_effect_system import get_status_effect_system
        body = await request.json()
        entity_id = body.get("entity_id", "")
        effect_id = body.get("effect_id", "")
        source_entity_id = body.get("source_entity_id", "")
        duration_override = body.get("duration_override")
        if duration_override is not None:
            duration_override = float(duration_override)
        intensity_override = body.get("intensity_override")
        if intensity_override is not None:
            intensity_override = float(intensity_override)
        engine = get_status_effect_system()
        active = engine.apply_effect(
            entity_id=entity_id,
            effect_id=effect_id,
            source_entity_id=source_entity_id,
            duration_override=duration_override,
            intensity_override=intensity_override,
        )
        if active is None:
            return JSONResponse(
                {"status": "error", "message": "Effect not applied (unknown effect or entity is immune)"},
                status_code=404,
            )
        return JSONResponse({"status": "success", "data": active.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


