@router.post("/memory-stream/memories")
async def memory_stream_record_memory(request: Request):
    """Record a new memory observation for an agent."""
    try:
        from sparkai.agent.agent_memory_stream import (
            get_memory_stream, MemoryType,
        )
        body = await request.json()
        agent_id = body.get("agent_id", "")
        if not agent_id:
            return JSONResponse(
                {"status": "error", "message": "agent_id is required"}, status_code=400
            )
        content = body.get("content", "")
        if not content:
            return JSONResponse(
                {"status": "error", "message": "content is required"}, status_code=400
            )
        try:
            memory_type = MemoryType(body.get("memory_type", "observation"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "Invalid memory_type"}, status_code=400
            )
        importance_score = float(body.get("importance_score", 5.0))
        engine = get_memory_stream()
        observation = engine.record_memory(
            agent_id=agent_id,
            memory_type=memory_type,
            content=content,
            importance_score=importance_score,
            location=body.get("location", ""),
            associated_agent_ids=body.get("associated_agent_ids"),
            timestamp=body.get("timestamp"),
            metadata=body.get("metadata"),
        )
        return JSONResponse({"status": "success", "data": observation.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


