@router.post("/memory-stream/memories/forget-old")
async def memory_stream_forget_old_memories(request: Request):
    """Forget memories older than max_age_hours with importance below min_importance."""
    try:
        from sparkai.agent.agent_memory_stream import get_memory_stream
        body = await request.json()
        agent_id = body.get("agent_id", "")
        if not agent_id:
            return JSONResponse(
                {"status": "error", "message": "agent_id is required"}, status_code=400
            )
        max_age_hours_raw = body.get("max_age_hours")
        if max_age_hours_raw is None:
            return JSONResponse(
                {"status": "error", "message": "max_age_hours is required"},
                status_code=400,
            )
        max_age_hours = float(max_age_hours_raw)
        min_importance = float(body.get("min_importance", 0))
        engine = get_memory_stream()
        forgotten_count = engine.forget_old_memories(
            agent_id=agent_id,
            max_age_hours=max_age_hours,
            min_importance=min_importance,
        )
        return JSONResponse(
            {"status": "success", "data": {"forgotten_count": forgotten_count}}
        )
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


