    """Register a new screen mode."""
    try:
        from sparkai.engine.engine_screen_manager import get_screen_manager
        body = await request.json()
        width = body.get("width")
        height = body.get("height")
        if width is None or height is None:
            return JSONResponse(
                {"status": "error", "message": "width and height are required"},
                status_code=400,
            )
        engine = get_screen_manager()
        mode = engine.register_mode(
            width=int(width),
            height=int(height),
            refresh_rate=float(body.get("refresh_rate", 60.0)),
            dpi=float(body.get("dpi", 96.0)),
            is_primary=bool(body.get("is_primary", False)),
            metadata=body.get("metadata"),
        )
        return JSONResponse({"status": "success", "data": mode.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


