@router.post("/screen-manager/scale")
async def screen_manager_compute_scale(request: Request):
    """Compute the scale factors and letterbox offsets for a fit."""
    try:
        from sparkai.engine.engine_screen_manager import (
            get_screen_manager, ScaleMode, LetterboxPolicy,
        )
        body = await request.json()
        target_width = body.get("target_width")
        target_height = body.get("target_height")
        if target_width is None or target_height is None:
            return JSONResponse(
                {"status": "error", "message": "target_width and target_height are required"},
                status_code=400,
            )
        try:
            scale_mode = ScaleMode(body.get("scale_mode", "show_all"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "Invalid scale_mode"},
                status_code=400,
            )
        try:
            letterbox_policy = LetterboxPolicy(body.get("letterbox_policy", "black_bars"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "Invalid letterbox_policy"},
                status_code=400,
            )
        engine = get_screen_manager()
        result = engine.compute_scale(
            target_width=float(target_width),
            target_height=float(target_height),
            mode_id=body.get("mode_id"),
            scale_mode=scale_mode,
            letterbox_policy=letterbox_policy,
        )
        return JSONResponse({"status": "success", "data": result.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


@router.post("/screen-manager/layouts")
async def screen_manager_create_layout(request: Request):
    """Create a new layout adaptation for a mode and orientation."""
    try:
        from sparkai.engine.engine_screen_manager import (
            get_screen_manager, Orientation,
        )
        body = await request.json()
        mode_id = body.get("mode_id")
        if mode_id is None:
            return JSONResponse(
                {"status": "error", "message": "mode_id is required"},
                status_code=400,
            )
        orientation_raw = body.get("orientation")
        if orientation_raw is None:
            return JSONResponse(
                {"status": "error", "message": "orientation is required"},
                status_code=400,
            )
        try:
            orientation = Orientation(orientation_raw)
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "Invalid orientation"},
                status_code=400,
            )
        engine = get_screen_manager()
        layout = engine.create_layout(
            name=body.get("name", ""),
            mode_id=mode_id,
            orientation=orientation,
            anchor_points=body.get("anchor_points"),
            element_scales=body.get("element_scales"),
            visible_elements=body.get("visible_elements"),
            hidden_elements=body.get("hidden_elements"),
            repositioned_elements=body.get("repositioned_elements"),
        )
        return JSONResponse({"status": "success", "data": layout.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


