@router.post("/screen-manager/profiles")
async def screen_manager_create_profile(request: Request):
    """Create a new screen profile."""
    try:
        from sparkai.engine.engine_screen_manager import (
            get_screen_manager, ScaleMode, LetterboxPolicy, DPIAwareness,
        )
        body = await request.json()
        default_mode_id = body.get("default_mode_id")
        if default_mode_id is None:
            return JSONResponse(
                {"status": "error", "message": "default_mode_id is required"},
                status_code=400,
            )
        try:
            scale_mode = ScaleMode(body.get("scale_mode"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "Invalid scale_mode"},
                status_code=400,
            )
        try:
            letterbox_policy = LetterboxPolicy(body.get("letterbox_policy"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "Invalid letterbox_policy"},
                status_code=400,
            )
        try:
            dpi_awareness = DPIAwareness(body.get("dpi_awareness"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "Invalid dpi_awareness"},
                status_code=400,
            )
        engine = get_screen_manager()
        profile = engine.create_profile(
            name=body.get("name", ""),
            description=body.get("description", ""),
            default_mode_id=default_mode_id,
            scale_mode=scale_mode,
            letterbox_policy=letterbox_policy,
            dpi_awareness=dpi_awareness,
            min_width=int(body.get("min_width", 320)),
            min_height=int(body.get("min_height", 240)),
            max_width=int(body.get("max_width", 7680)),
            max_height=int(body.get("max_height", 4320)),
        )
        return JSONResponse({"status": "success", "data": profile.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


