    """Register an agent with a susceptibility profile."""
    try:
        from sparkai.agent.agent_emotion_contagion import get_emotion_contagion
        body = await request.json()
        agent_id = body.get("agent_id")
        if not agent_id:
            return JSONResponse(
                {"status": "error", "message": "agent_id is required"},
                status_code=400,
            )
        engine = get_emotion_contagion()
        agent = engine.register_agent(
            agent_id=agent_id,
            base_susceptibility=float(body.get("base_susceptibility", 0.5)),
            social_resistance=float(body.get("social_resistance", 0.0)),
        )
        return JSONResponse({"status": "success", "data": agent.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


