@router.post("/emotion-contagion/connections")
async def emotion_contagion_connect_agents(request: Request):
    """Create or update a directed contagion link between two agents."""
    try:
        from sparkai.agent.agent_emotion_contagion import get_emotion_contagion
        body = await request.json()
        source_id = body.get("source_id")
        target_id = body.get("target_id")
        if not source_id or not target_id:
            return JSONResponse(
                {"status": "error", "message": "source_id and target_id are required"},
                status_code=400,
            )
        engine = get_emotion_contagion()
        link = engine.connect_agents(
            source_id=source_id,
            target_id=target_id,
            connection_strength=float(body.get("connection_strength", 0.5)),
        )
        return JSONResponse({"status": "success", "data": link.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


@router.delete("/emotion-contagion/connections/{source_id}/{target_id}")
async def emotion_contagion_disconnect_agents(source_id: str, target_id: str):
    """Remove the directed contagion link between two agents."""
    try:
        from sparkai.agent.agent_emotion_contagion import get_emotion_contagion
        engine = get_emotion_contagion()
        removed = engine.disconnect_agents(source_id, target_id)
        if not removed:
            return JSONResponse(
                {"status": "error", "message": "Connection not found"},
                status_code=404,
            )
        return JSONResponse({"status": "success", "data": {"removed": removed}})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


