@router.post("/emotion-contagion/emit")
async def emotion_contagion_emit_emotion(request: Request):
    """Emit an emotion from an agent and propagate it through the network."""
    try:
        from sparkai.agent.agent_emotion_contagion import (
            get_emotion_contagion, EmotionValence,
        )
        body = await request.json()
        agent_id = body.get("agent_id")
        emotion_name = body.get("emotion_name")
        intensity = body.get("intensity")
        if not agent_id or not emotion_name or intensity is None:
            return JSONResponse(
                {"status": "error", "message": "agent_id, emotion_name, and intensity are required"},
                status_code=400,
            )
        try:
            valence = EmotionValence(body.get("valence", "positive"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "Invalid valence"},
                status_code=400,
            )
        engine = get_emotion_contagion()
        signal = engine.emit_emotion(
            agent_id=agent_id,
            emotion_name=emotion_name,
            valence=valence,
            intensity=float(intensity),
            metadata=body.get("metadata"),
        )
        return JSONResponse({"status": "success", "data": signal.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


