@router.post("/narrative-memory/characters")
async def narrative_memory_register_character(request: Request):
    """Register a new character and create their character arc."""
    try:
        from sparkai.agent.agent_narrative_memory import (
            get_narrative_memory, CharacterRole,
        )
        body = await request.json()
        character_id = body.get("character_id", "")
        if not character_id:
            return JSONResponse(
                {"status": "error", "message": "character_id is required"},
                status_code=400,
            )
        character_name = body.get("character_name", "")
        if not character_name:
            return JSONResponse(
                {"status": "error", "message": "character_name is required"},
                status_code=400,
            )
        try:
            role = CharacterRole(body.get("role", "supporting"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "Invalid role"}, status_code=400
            )
        arc_summary = body.get("arc_summary", "")
        engine = get_narrative_memory()
        arc = engine.register_character(
            character_id=character_id,
            character_name=character_name,
            role=role,
            arc_summary=arc_summary,
        )
        return JSONResponse({"status": "success", "data": arc.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


