@router.post("/narrative-memory/events")
async def narrative_memory_record_event(request: Request):
    """Record a new narrative story event."""
    try:
        from sparkai.agent.agent_narrative_memory import (
            get_narrative_memory, StoryEventType,
        )
        body = await request.json()
        title = body.get("title", "")
        if not title:
            return JSONResponse(
                {"status": "error", "message": "title is required"}, status_code=400
            )
        description = body.get("description", "")
        if not description:
            return JSONResponse(
                {"status": "error", "message": "description is required"},
                status_code=400,
            )
        try:
            event_type = StoryEventType(body.get("event_type", "plot_point"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "Invalid event_type"}, status_code=400
            )
        engine = get_narrative_memory()
        event = engine.record_event(
            title=title,
            description=description,
            event_type=event_type,
            story_arc_id=body.get("story_arc_id", ""),
            participant_ids=body.get("participant_ids"),
            location=body.get("location", ""),
            timestamp=body.get("timestamp"),
            dramatic_weight=float(body.get("dramatic_weight", 0.5)),
            emotional_tone=body.get("emotional_tone", ""),
            tags=body.get("tags"),
            metadata=body.get("metadata"),
        )
        return JSONResponse({"status": "success", "data": event.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


