@router.patch("/vfx-graph/graphs/{graph_id}")
async def vfx_graph_update_graph(graph_id: str, request: Request):
    """Update any VFX graph fields by keyword arguments."""
    try:
        from sparkai.engine.engine_vfx_graph import (
            get_vfx_graph, RenderSpace, BlendMode, SortingMode,
        )
        body = await request.json()
        kwargs = {k: v for k, v in body.items() if v is not None}

        # Convert enum string values to their enum members.
        if "render_space" in kwargs:
            try:
                kwargs["render_space"] = RenderSpace(kwargs["render_space"])
            except ValueError:
                return JSONResponse({"status": "error", "message": "Invalid render_space"}, status_code=400)
        if "blend_mode" in kwargs:
            try:
                kwargs["blend_mode"] = BlendMode(kwargs["blend_mode"])
            except ValueError:
                return JSONResponse({"status": "error", "message": "Invalid blend_mode"}, status_code=400)
        if "sorting_mode" in kwargs:
            try:
                kwargs["sorting_mode"] = SortingMode(kwargs["sorting_mode"])
            except ValueError:
                return JSONResponse({"status": "error", "message": "Invalid sorting_mode"}, status_code=400)

        engine = get_vfx_graph()
        graph = engine.update_graph(graph_id, **kwargs)
        if graph is None:
            return JSONResponse({"status": "error", "message": "Graph not found"}, status_code=404)
        return JSONResponse({"status": "success", "data": graph.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


