@router.post("/vfx-graph/graphs/{graph_id}/connections")
async def vfx_graph_connect(graph_id: str, request: Request):
    """Connect two pins in a VFX graph, validating type and cycles."""
    try:
        from sparkai.engine.engine_vfx_graph import get_vfx_graph
        body = await request.json()
        source_node_id = body.get("source_node_id")
        source_pin_id = body.get("source_pin_id")
        target_node_id = body.get("target_node_id")
        target_pin_id = body.get("target_pin_id")
        if not all([source_node_id, source_pin_id, target_node_id, target_pin_id]):
            return JSONResponse({
                "status": "error",
                "message": "source_node_id, source_pin_id, target_node_id and target_pin_id are required",
            }, status_code=400)

        engine = get_vfx_graph()
        connection = engine.connect(
            graph_id, source_node_id, source_pin_id, target_node_id, target_pin_id,
        )
        if connection is None:
            return JSONResponse({
                "status": "error",
                "message": "Connection rejected (graph, node or pin not found, type mismatch, cycle, or duplicate)",
            }, status_code=400)
        return JSONResponse({"status": "success", "data": connection.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


