# Capability management


@router.post("/self-model/agents/{agent_id}/capabilities")
async def self_model_add_capability(agent_id: str, request: Request):
    """Add a capability to an agent's self-model."""
    try:
        from sparkai.agent.agent_self_model import get_self_model
        body = await request.json()
        name = body.get("name")
        if not name or not isinstance(name, str):
            return JSONResponse(
                {"status": "error", "message": "name is required"},
                status_code=400,
            )
        description = body.get("description", "")
        proficiency = body.get("proficiency", 0.5)
        confidence = body.get("confidence", 0.5)
        engine = get_self_model()
        entry = engine.add_capability(
            agent_id,
            name,
            description=description,
            proficiency=proficiency,
            confidence=confidence,
        )
        if entry is None:
            return JSONResponse(
                {"status": "error", "message": "Agent not found"},
                status_code=404,
            )
        return JSONResponse({"status": "success", "data": entry.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


