# Limit management


@router.post("/self-model/agents/{agent_id}/limits")
async def self_model_register_limit(agent_id: str, request: Request):
    """Register a limit on an agent's self-model."""
    try:
        from sparkai.agent.agent_self_model import get_self_model, LimitType
        body = await request.json()
        name = body.get("name")
        limit_type_value = body.get("limit_type")
        if not name or not isinstance(name, str):
            return JSONResponse(
                {"status": "error", "message": "name is required"},
                status_code=400,
            )
        if not limit_type_value or not isinstance(limit_type_value, str):
            return JSONResponse(
                {"status": "error", "message": "limit_type is required"},
                status_code=400,
            )
        try:
            limit_type = LimitType(limit_type_value)
        except ValueError:
            return JSONResponse(
                {
                    "status": "error",
                    "message": f"Invalid limit_type: {limit_type_value}",
                },
                status_code=400,
            )
        threshold = body.get("threshold", 0.0)
        unit = body.get("unit", "")
        hard_limit = body.get("hard_limit", True)
        engine = get_self_model()
        entry = engine.register_limit(
            agent_id,
            name,
            limit_type,
            threshold=threshold,
            unit=unit,
            hard_limit=hard_limit,
        )
        if entry is None:
            return JSONResponse(
                {"status": "error", "message": "Agent not found"},
                status_code=404,
            )
        return JSONResponse({"status": "success", "data": entry.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


