# Revisions


@router.post("/self-model/agents/{agent_id}/revisions")
async def self_model_apply_revision(agent_id: str, request: Request):
    """Record a self-model revision for an agent."""
    try:
        from sparkai.agent.agent_self_model import get_self_model
        body = await request.json()
        trigger = body.get("trigger")
        reason = body.get("reason")
        changes = body.get("changes", [])
        if not trigger or not isinstance(trigger, str):
            return JSONResponse(
                {"status": "error", "message": "trigger is required"},
                status_code=400,
            )
        if not reason or not isinstance(reason, str):
            return JSONResponse(
                {"status": "error", "message": "reason is required"},
                status_code=400,
            )
        if not isinstance(changes, list):
            return JSONResponse(
                {
                    "status": "error",
                    "message": "changes must be a list of dicts",
                },
                status_code=400,
            )
        engine = get_self_model()
        revision = engine.apply_revision(agent_id, trigger, reason, changes)
        if revision is None:
            return JSONResponse(
                {"status": "error", "message": "Agent not found"},
                status_code=404,
            )
        return JSONResponse({"status": "success", "data": revision.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


@router.get("/self-model/agents/{agent_id}/revisions")
async def self_model_list_revisions(agent_id: str, request: Request):
    """List recent revisions for an agent."""
    try:
        from sparkai.agent.agent_self_model import get_self_model
        limit_raw = request.query_params.get("limit", "20")
        try:
            limit = int(limit_raw)
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "limit must be an integer"},
                status_code=400,
            )
        engine = get_self_model()
        revisions = engine.list_revisions(agent_id, limit=limit)
        return JSONResponse(
            {"status": "success", "data": [r.to_dict() for r in revisions]}
        )
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


