@router.get("/social-network/agents/{agent_id}/neighbors")
async def social_network_get_neighbors(request: Request, agent_id: str):
    """Return agents directly connected to the given agent."""
    try:
        from sparkai.agent.agent_social_network_analysis import get_social_network_analysis
        include_bidirectional_raw = request.query_params.get("include_bidirectional", "true")
        include_bidirectional = include_bidirectional_raw.lower() in ("1", "true", "yes", "on")
        engine = get_social_network_analysis()
        if engine.get_agent(agent_id) is None:
            return JSONResponse(
                {"status": "error", "message": f"Agent not found: {agent_id}"},
                status_code=404,
            )
        neighbors = engine.get_neighbors(agent_id, include_bidirectional=include_bidirectional)
        return JSONResponse(
            {"status": "success", "data": [n.to_dict() for n in neighbors]}
        )
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


# ---------------------------------------------------------------------------
# Edge management
# ---------------------------------------------------------------------------

@router.post("/social-network/edges")
async def social_network_add_edge(request: Request):
    """Add a weighted edge between two agents in the social graph."""
    try:
        from sparkai.agent.agent_social_network_analysis import get_social_network_analysis
        body = await request.json()
        source_id = body.get("source_id")
        target_id = body.get("target_id")
        if not source_id or not isinstance(source_id, str):
            return JSONResponse(
                {"status": "error", "message": "source_id is required"},
                status_code=400,
            )
        if not target_id or not isinstance(target_id, str):
            return JSONResponse(
                {"status": "error", "message": "target_id is required"},
                status_code=400,
            )
        weight = float(body.get("weight", 1.0))
        relationship_type = body.get("relationship_type", "general")
        bidirectional = bool(body.get("bidirectional", True))
        engine = get_social_network_analysis()
        edge = engine.add_edge(
            source_id=source_id,
            target_id=target_id,
            weight=weight,
            relationship_type=relationship_type,
            bidirectional=bidirectional,
        )
        if edge is None:
            return JSONResponse(
                {"status": "error", "message": "Self-loop edges are not allowed"},
                status_code=400,
            )
        return JSONResponse({"status": "success", "data": edge.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


