@router.post("/tool-synthesis/primitives")
async def tool_synthesis_add_primitive(request: Request):
    """Register a new primitive specification in the synthesis catalogue."""
    try:
        from sparkai.agent.agent_tool_synthesis import get_tool_synthesis, PrimitiveType
        body = await request.json()
        name = body.get("name", "")
        if not name:
            return JSONResponse({"status": "error", "message": "name is required"}, status_code=400)

        primitive_type_str = body.get("primitive_type")
        if not primitive_type_str:
            return JSONResponse({"status": "error", "message": "primitive_type is required"}, status_code=400)
        try:
            primitive_type = PrimitiveType(primitive_type_str)
        except ValueError:
            return JSONResponse({"status": "error", "message": "Invalid primitive_type"}, status_code=400)

        input_signature = body.get("input_signature", "any")
        output_signature = body.get("output_signature", "any")
        description = body.get("description", "")
        implementation_hint = body.get("implementation_hint", "")

        engine = get_tool_synthesis()
        spec = engine.add_primitive(
            name=name,
            primitive_type=primitive_type,
            input_signature=input_signature,
            output_signature=output_signature,
            description=description,
            implementation_hint=implementation_hint,
        )
        return JSONResponse({"status": "success", "data": spec.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


