@router.post("/tool-synthesis/tools")
async def tool_synthesis_synthesize_tool(request: Request):
    """Synthesize a brand-new tool definition from a set of primitives."""
    try:
        from sparkai.agent.agent_tool_synthesis import (
            get_tool_synthesis, ToolParameter, ToolStep,
        )
        body = await request.json()
        name = body.get("name", "")
        description = body.get("description", "")
        requester_agent_id = body.get("requester_agent_id", "")
        intent = body.get("intent", "")
        available_primitive_ids = body.get("available_primitive_ids", [])

        if not name:
            return JSONResponse({"status": "error", "message": "name is required"}, status_code=400)
        if not requester_agent_id:
            return JSONResponse({"status": "error", "message": "requester_agent_id is required"}, status_code=400)
        if not available_primitive_ids:
            return JSONResponse({"status": "error", "message": "available_primitive_ids is required"}, status_code=400)

        # Convert the optional parameters list of dicts into ToolParameter instances.
        parameters = None
        raw_params = body.get("parameters")
        if raw_params is not None:
            parameters = []
            for entry in raw_params:
                if not isinstance(entry, dict):
                    continue
                param_type_str = entry.get("param_type", "any")
                try:
                    from sparkai.agent.agent_tool_synthesis import ParameterType
                    param_type = ParameterType(param_type_str)
                except ValueError:
                    return JSONResponse({
                        "status": "error",
                        "message": f"Invalid param_type '{param_type_str}'",
                    }, status_code=400)
                parameters.append(
                    ToolParameter(
                        param_id=entry.get("param_id", ""),
                        name=entry.get("name", ""),
                        param_type=param_type,
                        required=bool(entry.get("required", True)),
                        default_value=entry.get("default_value"),
                        description=entry.get("description", ""),
                        validation_rule=entry.get("validation_rule", ""),
                    )
                )

        # Convert the optional steps list of dicts into ToolStep instances.
        steps = None
        raw_steps = body.get("steps")
        if raw_steps is not None:
            steps = []
            for entry in raw_steps:
                if not isinstance(entry, dict):
                    continue
                steps.append(
                    ToolStep(
                        step_id=entry.get("step_id", ""),
                        step_index=int(entry.get("step_index", 0)),
                        primitive_id=entry.get("primitive_id", ""),
                        input_mapping=entry.get("input_mapping") or {},
                        output_name=entry.get("output_name", ""),
                        conditional=entry.get("conditional"),
                    )
                )

        strategy = body.get("strategy", "composition")

        engine = get_tool_synthesis()
        tool = engine.synthesize_tool(
            name=name,
            description=description,
            requester_agent_id=requester_agent_id,
            intent=intent,
            available_primitive_ids=available_primitive_ids,
            parameters=parameters,
            strategy=strategy,
            steps=steps,
        )
        return JSONResponse({"status": "success", "data": tool.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


