@router.post("/tool-synthesis/tools/{tool_id}/steps")
async def tool_synthesis_add_step(tool_id: str, request: Request):
    """Append a step to a synthesized tool's pipeline."""
    try:
        from sparkai.agent.agent_tool_synthesis import get_tool_synthesis
        body = await request.json()
        primitive_id = body.get("primitive_id", "")
        if not primitive_id:
            return JSONResponse({"status": "error", "message": "primitive_id is required"}, status_code=400)

        input_mapping = body.get("input_mapping")
        if input_mapping is not None and not isinstance(input_mapping, dict):
            return JSONResponse({"status": "error", "message": "input_mapping must be a dict"}, status_code=400)
        output_name = body.get("output_name", "")
        conditional = body.get("conditional")

        engine = get_tool_synthesis()
        step = engine.add_step(
            tool_id=tool_id,
            primitive_id=primitive_id,
            input_mapping=input_mapping,
            output_name=output_name,
            conditional=conditional,
        )
        if step is None:
            return JSONResponse({"status": "error", "message": "Tool not found"}, status_code=404)
        return JSONResponse({"status": "success", "data": step.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


