@router.post("/goal-negotiation/goals")
async def goal_negotiation_propose_goal(request: Request):
    """Propose a new goal to the negotiation ledger."""
    try:
        from sparkai.agent.agent_goal_negotiation_ledger import (
            get_goal_negotiation_ledger, GoalPriority,
        )
        body = await request.json()
        proposer_id = body.get("proposer_id", "")
        title = body.get("title", "")
        if not proposer_id:
            return JSONResponse({"status": "error", "message": "proposer_id is required"}, status_code=400)
        if not title:
            return JSONResponse({"status": "error", "message": "title is required"}, status_code=400)

        # Convert priority string to GoalPriority enum with fallback.
        priority_value = body.get("priority", "medium")
        try:
            priority_enum = GoalPriority(str(priority_value).strip().lower())
        except ValueError:
            return JSONResponse({"status": "error", "message": "Invalid priority value"}, status_code=400)

        engine = get_goal_negotiation_ledger()
        proposal = engine.propose_goal(
            proposer_id=proposer_id,
            title=title,
            description=body.get("description", ""),
            priority=priority_enum.value,
            required_participants=body.get("required_participants"),
            deadline=body.get("deadline"),
        )
        return JSONResponse({"status": "success", "data": proposal.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


