@router.post("/goal-negotiation/negotiations/{negotiation_id}/pledges")
async def goal_negotiation_make_pledge(negotiation_id: str, request: Request):
    """Register a new pledge within a negotiation."""
    try:
        from sparkai.agent.agent_goal_negotiation_ledger import (
            get_goal_negotiation_ledger, PledgeType,
        )
        body = await request.json()
        pledger_id = body.get("pledger_id", "")
        pledge_type_str = body.get("pledge_type", "action")
        description = body.get("description", "")
        if not pledger_id:
            return JSONResponse({"status": "error", "message": "pledger_id is required"}, status_code=400)
        if not description:
            return JSONResponse({"status": "error", "message": "description is required"}, status_code=400)

        # Convert pledge_type string to PledgeType enum with fallback.
        try:
            pledge_type_enum = PledgeType(str(pledge_type_str).strip().lower())
        except ValueError:
            return JSONResponse({"status": "error", "message": "Invalid pledge_type value"}, status_code=400)

        # Validate commitment_strength if provided.
        commitment_strength = 0.5
        if "commitment_strength" in body and body["commitment_strength"] is not None:
            try:
                commitment_strength = float(body["commitment_strength"])
            except (TypeError, ValueError):
                return JSONResponse({"status": "error", "message": "commitment_strength must be a number"}, status_code=400)

        engine = get_goal_negotiation_ledger()
        pledge = engine.make_pledge(
            negotiation_id=negotiation_id,
            pledger_id=pledger_id,
            pledge_type=pledge_type_enum.value,
            description=description,
            commitment_strength=commitment_strength,
            resource_amount=body.get("resource_amount"),
            action_steps=body.get("action_steps"),
        )
        if pledge is None:
            return JSONResponse({"status": "error", "message": "negotiation not found or closed"}, status_code=404)
        return JSONResponse({"status": "success", "data": pledge.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


