@router.patch("/learning-analytics/units/{agent_id}/{unit_id}")
async def learning_analytics_update_unit(agent_id: str, unit_id: str, request: Request):
    """Update fields on a knowledge unit."""
    try:
        from sparkai.agent.agent_learning_analytics import (
            get_learning_analytics, KnowledgeState, MasteryLevel, LearningPhase,
        )
        body = await request.json()

        # Convert enum string values to their enum members if provided.
        if "knowledge_state" in body and body["knowledge_state"] is not None:
            try:
                body["knowledge_state"] = KnowledgeState(body["knowledge_state"])
            except ValueError:
                return JSONResponse({"status": "error", "message": "Invalid knowledge_state"}, status_code=400)

        if "mastery_level" in body and body["mastery_level"] is not None:
            try:
                body["mastery_level"] = MasteryLevel(body["mastery_level"])
            except ValueError:
                return JSONResponse({"status": "error", "message": "Invalid mastery_level"}, status_code=400)

        if "learning_phase" in body and body["learning_phase"] is not None:
            try:
                body["learning_phase"] = LearningPhase(body["learning_phase"])
            except ValueError:
                return JSONResponse({"status": "error", "message": "Invalid learning_phase"}, status_code=400)

        engine = get_learning_analytics()
        unit = engine.update_unit(agent_id=agent_id, unit_id=unit_id, **body)
        if unit is None:
            return JSONResponse({"status": "error", "message": "Unit not found"}, status_code=404)
        return JSONResponse({"status": "success", "data": unit.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


