@router.post("/concept-drift/concepts")
async def concept_drift_register_concept(request: Request):
    """Register a new concept for an agent."""
    try:
        from sparkai.agent.agent_concept_drift import (
            get_concept_drift, ConceptType,
        )
        body = await request.json()
        agent_id = body.get("agent_id", "")
        if not agent_id:
            return JSONResponse(
                {"status": "error", "message": "agent_id is required"}, status_code=400
            )
        name = body.get("name", "")
        if not name:
            return JSONResponse(
                {"status": "error", "message": "name is required"}, status_code=400
            )
        try:
            concept_type = ConceptType(body.get("concept_type", "object"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "Invalid concept_type"}, status_code=400
            )
        prototype = body.get("prototype")
        engine = get_concept_drift()
        concept = engine.register_concept(
            agent_id=agent_id,
            name=name,
            concept_type=concept_type,
            prototype=prototype,
            description=body.get("description", ""),
            tags=body.get("tags"),
        )
        if concept is None:
            return JSONResponse(
                {"status": "error", "message": "Agent not found"}, status_code=404
            )
        return JSONResponse({"status": "success", "data": concept.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


