@router.post("/world-anchoring/bindings")
async def world_anchoring_bind(request: Request):
    """Bind an anchor to a world entity."""
    try:
        from sparkai.agent.agent_world_anchoring import (
            get_world_anchoring, EntityType, ReferenceFrame,
        )
        body = await request.json()
        agent_id = body.get("agent_id", "")
        anchor_id = body.get("anchor_id", "")
        entity_id = body.get("entity_id", "")
        if not all([agent_id, anchor_id, entity_id]):
            return JSONResponse(
                {"status": "error", "message": "agent_id, anchor_id, entity_id are required"},
                status_code=400,
            )
        try:
            entity_type = EntityType(body.get("entity_type", "object"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "Invalid entity_type"}, status_code=400
            )
        frame_str = body.get("frame", "absolute")
        try:
            frame = ReferenceFrame(frame_str)
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "Invalid frame"}, status_code=400
            )
        engine = get_world_anchoring()
        binding = engine.bind_to_entity(
            agent_id=agent_id,
            anchor_id=anchor_id,
            entity_id=entity_id,
            entity_type=entity_type,
            frame=frame,
            confidence=float(body.get("confidence", 0.5)),
            evidence=body.get("evidence"),
        )
        if binding is None:
            return JSONResponse(
                {"status": "error", "message": "Anchor not found"}, status_code=404
            )
        return JSONResponse({"status": "success", "data": binding.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


