@router.post("/hot-reload/watches")
async def hot_reload_add_watch(request: Request):
    """Add a new path to be watched for file changes."""
    try:
        from sparkai.engine.engine_hot_reload_watcher import (
            get_hot_reload_watcher, FileType,
        )
        body = await request.json()
        path = body.get("path", "")
        if not path:
            return JSONResponse(
                {"status": "error", "message": "path is required"}, status_code=400
            )
        file_types_str = body.get("file_types", [])
        file_types = []
        for ft in file_types_str:
            try:
                file_types.append(FileType(ft))
            except ValueError:
                pass
        recursive = bool(body.get("recursive", True))
        engine = get_hot_reload_watcher()
        target = engine.add_watch(
            path=path,
            file_types=file_types,
            recursive=recursive,
            metadata=body.get("metadata"),
        )
        if target is None:
            return JSONResponse(
                {"status": "error", "message": "Path rejected by filters"}, status_code=400
            )
        return JSONResponse({"status": "success", "data": target.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


