@router.post("/hot-reload/subscribers")
async def hot_reload_subscribe(request: Request):
    """Register a new subscriber for change notifications."""
    try:
        from sparkai.engine.engine_hot_reload_watcher import (
            get_hot_reload_watcher, ChangeKind, ReloadStrategy,
        )
        body = await request.json()
        subscriber_id = body.get("subscriber_id", "")
        if not subscriber_id:
            return JSONResponse(
                {"status": "error", "message": "subscriber_id is required"}, status_code=400
            )
        paths = body.get("paths", [])
        kinds_str = body.get("kinds", [])
        kinds = []
        for k in kinds_str:
            try:
                kinds.append(ChangeKind(k))
            except ValueError:
                pass
        try:
            strategy = ReloadStrategy(body.get("strategy", "immediate"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": "Invalid strategy"}, status_code=400
            )
        engine = get_hot_reload_watcher()
        sub = engine.subscribe(
            subscriber_id=subscriber_id,
            paths=paths,
            kinds=kinds,
            strategy=strategy,
        )
        if sub is None:
            return JSONResponse(
                {"status": "error", "message": "Subscribe rejected"}, status_code=400
            )
        return JSONResponse({"status": "success", "data": sub.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


