@router.post("/player-journey/sessions/{session_id}/end")
async def player_journey_end_session(session_id: str, request: Request):
    """End an active player session."""
    try:
        from sparkai.engine.engine_player_journey import (
            get_player_journey, JourneyStage,
        )
        body = await request.json()
        drop_off_stage = ""
        raw_stage = body.get("drop_off_stage", "")
        if raw_stage:
            try:
                drop_off_stage = JourneyStage(raw_stage).value
            except ValueError:
                drop_off_stage = str(raw_stage)
        engine = get_player_journey()
        s = engine.end_session(session_id, drop_off_stage)
        if s is None:
            return JSONResponse(
                {"status": "error", "message": "Session not found"}, status_code=404
            )
        return JSONResponse({"status": "success", "data": s.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


