@router.post("/block-programmer/block-types")
async def block_programmer_register_block_type(request: Request):
    """Register a new reusable block type."""
    try:
        from sparkai.agent.agent_block_programmer import get_block_programmer
        body = await request.json()
        type_id = body.get("type_id", "")
        if not type_id:
            return JSONResponse(
                {"status": "error", "message": "type_id is required"}, status_code=400
            )
        engine = get_block_programmer()
        bt = engine.register_block_type(
            type_id=type_id,
            name=body.get("name", type_id),
            category=body.get("category", "action"),
            description=body.get("description", ""),
            params=body.get("params", []),
            returns=body.get("returns", "boolean"),
            can_terminate=body.get("can_terminate", False),
        )
        if bt is None:
            return JSONResponse(
                {"status": "error", "message": "Block type already exists or invalid"},
                status_code=400,
            )
        return JSONResponse({"status": "success", "data": bt.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


