@router.patch("/block-programmer/programs/{program_id}")
async def block_programmer_update_program(program_id: str, request: Request):
    """Rename or re-describe a program, or add a tag."""
    try:
        from sparkai.agent.agent_block_programmer import get_block_programmer
        body = await request.json()
        engine = get_block_programmer()
        if "name" in body or "description" in body:
            program = engine.rename_program(
                program_id,
                body.get("name", ""),
                body.get("description", ""),
            )
        elif "tag" in body:
            program = engine.tag_program(program_id, body.get("tag", ""))
        else:
            program = engine.get_program(program_id)
        if program is None:
            return JSONResponse(
                {"status": "error", "message": "Program not found"}, status_code=404
            )
        return JSONResponse({"status": "success", "data": program.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


@router.post("/block-programmer/programs/{program_id}/blocks")
async def block_programmer_add_block(program_id: str, request: Request):
    """Append a block to a program."""
    try:
        from sparkai.agent.agent_block_programmer import get_block_programmer
        body = await request.json()
        type_id = body.get("type_id", "")
        if not type_id:
            return JSONResponse(
                {"status": "error", "message": "type_id is required"}, status_code=400
            )
        engine = get_block_programmer()
        block = engine.add_block(
            program_id=program_id,
            type_id=type_id,
            params=body.get("params", {}),
        )
        if block is None:
            return JSONResponse(
                {"status": "error", "message": "Program or block type not found"},
                status_code=404,
            )
        return JSONResponse({"status": "success", "data": block.to_dict()})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


@router.post("/block-programmer/programs/{program_id}/blocks/{instance_id}/move")
async def block_programmer_move_block(
    program_id: str, instance_id: str, request: Request
):
    """Move a block to a new position in the stack."""
    try:
        from sparkai.agent.agent_block_programmer import get_block_programmer
        body = await request.json()
        position = int(body.get("position", 0))
        engine = get_block_programmer()
        ok = engine.move_block(program_id, instance_id, position)
        if not ok:
            return JSONResponse(
                {"status": "error", "message": "Program or block not found"},
                status_code=404,
            )
        program = engine.get_program(program_id)
        return JSONResponse(
            {"status": "success", "data": program.to_dict() if program else None}
        )
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


@router.patch("/block-programmer/programs/{program_id}/blocks/{instance_id}")
async def block_programmer_update_block(
    program_id: str, instance_id: str, request: Request
):
    """Update a block's parameters or enabled state."""
    try:
        from sparkai.agent.agent_block_programmer import get_block_programmer
        body = await request.json()
        engine = get_block_programmer()
        if "enabled" in body:
            ok = engine.set_block_enabled(
                program_id, instance_id, bool(body.get("enabled"))
            )
        elif "params" in body:
            ok = engine.update_block_params(
                program_id, instance_id, body.get("params", {})
            )
        else:
            ok = False
        if not ok:
            return JSONResponse(
                {"status": "error", "message": "Program or block not found"},
                status_code=404,
            )
        program = engine.get_program(program_id)
        return JSONResponse(
            {"status": "success", "data": program.to_dict() if program else None}
        )
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


