# ===========================================================================
# Section 112: Block Deployment Bridge (Block Programmer -> Block Runtime)
# ===========================================================================


@router.post("/block-deployment/deploy/{program_id}")
async def block_deployment_deploy(program_id: str):
    """Deploy a published block program into the runtime executor.

    Fetches the program from the Block Programmer agent, loads it into the
    Block Runtime executor, starts it, and binds its event blocks to the
    runtime. This bridges AI-composed programs to live game execution.
    """
    try:
        from sparkai.agent.agent_block_programmer import get_block_programmer
        from sparkai.engine.engine_block_runtime import get_block_runtime

        programmer = get_block_programmer()
        runtime = get_block_runtime()

        program = programmer.get_program(program_id)
        if program is None:
            return JSONResponse(
                {"status": "error", "message": "Program not found"}, status_code=404
            )

        blocks_data = [b.to_dict() for b in program.blocks]
        loaded = runtime.load_program(
            program_id=program_id,
            name=program.name,
            blocks=blocks_data,
        )
        runtime.start_program(loaded.runtime_id)

        bound_events: List[str] = []
        for block in program.blocks:
            if block.category.value == "event":
                runtime.bind_event(loaded.runtime_id, block.type_id, {})
                bound_events.append(block.type_id)

        return JSONResponse({
            "status": "success",
            "data": {
                "runtime_id": loaded.runtime_id,
                "program_id": program_id,
                "program_name": program.name,
                "block_count": len(program.blocks),
                "bound_events": bound_events,
                "status": loaded.status.value,
            },
        })
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


@router.get("/block-deployment/status")
async def block_deployment_status():
    """Get a combined status of the Block Programmer and Runtime.

    Returns a unified view showing how many programs are composed,
    published, and actively running — useful for the editor dashboard.
    """
    try:
        from sparkai.agent.agent_block_programmer import get_block_programmer
        from sparkai.engine.engine_block_runtime import get_block_runtime

        programmer = get_block_programmer()
        runtime = get_block_runtime()

        programmer_status = programmer.get_status()
        runtime_status = runtime.get_status()

        published_programs = [
            p.to_dict() for p in programmer.list_programs(status="published")
        ]
        running_programs = [
            p.to_dict() for p in runtime.list_programs(status="running")
        ]

        return JSONResponse({
            "status": "success",
            "data": {
                "programmer": programmer_status,
                "runtime": runtime_status,
                "published_programs": published_programs,
                "running_programs": running_programs,
                "pipeline": {
                    "composed": programmer_status["total_programs"],
                    "published": len(published_programs),
                    "deployed": runtime_status["total_programs"],
                    "running": runtime_status["active_programs"],
                },
            },
        })
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


