@router.post("/timeline-sequencer/playbacks/{playback_id}/tick")
async def timeline_sequencer_tick(playback_id: str, request: Request):
    """Advance a playback by delta_time and return fired keyframes."""
    try:
        from sparkai.engine.engine_timeline_sequencer import get_timeline_sequencer
        body = await request.json()
        delta = float(body.get("delta_time", 0.016))
        engine = get_timeline_sequencer()
        fired = engine.tick(playback_id, delta)
        pb = engine.get_playback(playback_id)
        return JSONResponse({
            "status": "success",
            "data": {
                "playback": pb.to_dict() if pb else None,
                "fired_keyframes": [k.to_dict() for k in fired],
            },
        })
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


