@router.post("/experiment-framework/experiments")
async def experiment_framework_create_experiment(request: Request):
    """Create a new experiment."""
    try:
        from sparkai.engine.engine_experiment_framework import (
            get_experiment_framework, AllocationStrategy, SignificanceLevel,
        )
        engine = get_experiment_framework()
        body = await request.json()
        allocation = AllocationStrategy(body.get("allocation", "equal"))
        sig_level = SignificanceLevel(body.get("significance_level", "p95"))
        exp = engine.create_experiment(
            name=body.get("name", ""),
            description=body.get("description", ""),
            allocation=allocation,
            significance_level=sig_level,
            traffic_percentage=float(body.get("traffic_percentage", 100.0)),
        )
        return JSONResponse({"status": "success", "data": exp.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


