@router.post("/balance-system/rules")
async def balance_system_create_rule(request: Request):
    """Create a declarative auto-tuning rule."""
    try:
        from sparkai.engine.engine_balance_system import get_balance_system, RuleOperator, RuleAction
        body = await request.json()
        try:
            op = RuleOperator(body.get("operator", ">"))
            action = RuleAction(body.get("action", "increase"))
        except ValueError as e:
            return JSONResponse(
                {"status": "error", "message": f"invalid enum: {e}"},
                status_code=400,
            )
        engine = get_balance_system()
        rule = engine.create_rule(
            name=body.get("name", ""),
            parameter_id=body.get("parameter_id", ""),
            metric=body.get("metric", "win_rate"),
            operator=op,
            threshold=float(body.get("threshold", 0.0)),
            action=action,
            magnitude=float(body.get("magnitude", 0.1)),
            target_value=body.get("target_value"),
            description=body.get("description", ""),
        )
        if rule is None:
            return JSONResponse(
                {"status": "error", "message": "parameter not found"},
                status_code=404,
            )
        return JSONResponse({"status": "success", "data": rule.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


