@router.post("/procedural-music/compositions/{composition_id}/tracks/{track_id}/measures")
async def procedural_music_add_measure(composition_id: str, track_id: str, request: Request):
    """Add a measure to a track."""
    try:
        from sparkai.engine.engine_procedural_music import get_procedural_music_composer
        body = await request.json()
        engine = get_procedural_music_composer()
        ts_raw = body.get("time_signature", [4, 4])
        if isinstance(ts_raw, list) and len(ts_raw) == 2:
            ts = (int(ts_raw[0]), int(ts_raw[1]))
        else:
            ts = (4, 4)
        measure = engine.add_measure(
            composition_id=composition_id,
            track_id=track_id,
            time_signature=ts,
            notes=body.get("notes"),
        )
        if measure is None:
            return JSONResponse(
                {"status": "error", "message": "composition, track not found, or measure cap reached"},
                status_code=404,
            )
        return JSONResponse({"status": "success", "data": measure.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


