@router.post("/procedural-music/motifs")
async def procedural_music_compose_motif(request: Request):
    """Compose a new melodic motif."""
    try:
        from sparkai.engine.engine_procedural_music import (
            get_procedural_music_composer, ScaleType,
        )
        body = await request.json()
        try:
            scale = ScaleType(body.get("scale", "major"))
        except ValueError as e:
            return JSONResponse(
                {"status": "error", "message": f"invalid scale: {e}"},
                status_code=400,
            )
        engine = get_procedural_music_composer()
        seed_raw = body.get("seed")
        seed = int(seed_raw) if seed_raw is not None else None
        motif = engine.compose_motif(
            name=body.get("name", ""),
            key_root=int(body.get("key_root", 0)),
            scale=scale,
            num_notes=int(body.get("num_notes", 8)),
            seed=seed,
        )
        return JSONResponse({"status": "success", "data": motif.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


