@router.post("/procedural-music/templates")
async def procedural_music_create_template(request: Request):
    """Create a reusable composition template."""
    try:
        from sparkai.engine.engine_procedural_music import (
            get_procedural_music_composer, Genre, ScaleType, TrackRole,
        )
        body = await request.json()
        try:
            genre = Genre(body.get("genre", "fantasy"))
            scale = ScaleType(body.get("default_scale", "major"))
        except ValueError as e:
            return JSONResponse(
                {"status": "error", "message": f"invalid enum: {e}"},
                status_code=400,
            )
        track_roles_raw = body.get("track_roles", ["melody"])
        track_roles = []
        for r in track_roles_raw:
            try:
                track_roles.append(TrackRole(r))
            except ValueError:
                return JSONResponse(
                    {"status": "error", "message": f"invalid track role: {r}"},
                    status_code=400,
                )
        engine = get_procedural_music_composer()
        template = engine.create_template(
            name=body.get("name", ""),
            genre=genre,
            default_tempo=int(body.get("default_tempo", 120)),
            default_key=int(body.get("default_key", 0)),
            default_scale=scale,
            track_roles=track_roles,
            progression_name=body.get("progression_name", "I-IV-V-I"),
            description=body.get("description", ""),
        )
        return JSONResponse({"status": "success", "data": template.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


