@router.post("/game-critic/sessions/{session_id}/scores")
async def game_critic_score_criterion(session_id: str, request: Request):
    """Assign a score (0-10) to a review dimension."""
    try:
        from sparkai.agent.agent_game_critic import get_game_critic, ReviewDimension
        body = await request.json()
        try:
            dim = ReviewDimension(body.get("dimension", "fun"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": f"invalid dimension: {body.get('dimension')}"},
                status_code=400,
            )
        engine = get_game_critic()
        score = engine.score_criterion(
            session_id=session_id,
            dimension=dim,
            score=float(body.get("score", 0.0)),
            notes=body.get("notes", ""),
        )
        if score is None:
            return JSONResponse(
                {"status": "error", "message": "session not found or score cap reached"},
                status_code=404,
            )
        return JSONResponse({"status": "success", "data": score.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


