@router.post("/game-critic/sessions/{session_id}/findings")
async def game_critic_add_finding(session_id: str, request: Request):
    """Add a qualitative finding to a review session."""
    try:
        from sparkai.agent.agent_game_critic import (
            get_game_critic, FindingCategory, SeverityLevel, ReviewDimension,
        )
        body = await request.json()
        try:
            category = FindingCategory(body.get("category", "observation"))
            severity = SeverityLevel(body.get("severity", "info"))
            dimension = ReviewDimension(body.get("dimension", "fun"))
        except ValueError as e:
            return JSONResponse(
                {"status": "error", "message": f"invalid enum: {e}"},
                status_code=400,
            )
        engine = get_game_critic()
        finding = engine.add_finding(
            session_id=session_id,
            category=category,
            severity=severity,
            dimension=dimension,
            title=body.get("title", ""),
            description=body.get("description", ""),
            location=body.get("location", ""),
        )
        if finding is None:
            return JSONResponse(
                {"status": "error", "message": "session not found or finding cap reached"},
                status_code=404,
            )
        return JSONResponse({"status": "success", "data": finding.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


@router.get("/game-critic/sessions/{session_id}/findings")
async def game_critic_list_findings(session_id: str, request: Request):
    """List findings for a session, optionally filtered."""
    try:
        from sparkai.agent.agent_game_critic import (
            get_game_critic, FindingCategory, ReviewDimension,
        )
        engine = get_game_critic()
        cat_raw = request.query_params.get("category")
        dim_raw = request.query_params.get("dimension")
        cat_enum = None
        dim_enum = None
        if cat_raw:
            try:
                cat_enum = FindingCategory(cat_raw)
            except ValueError:
                return JSONResponse(
                    {"status": "error", "message": f"invalid category: {cat_raw}"},
                    status_code=400,
                )
        if dim_raw:
            try:
                dim_enum = ReviewDimension(dim_raw)
            except ValueError:
                return JSONResponse(
                    {"status": "error", "message": f"invalid dimension: {dim_raw}"},
                    status_code=400,
                )
        items = engine.list_findings(
            session_id=session_id, category=cat_enum, dimension=dim_enum,
        )
        return JSONResponse({"status": "success", "data": [f.to_dict() for f in items]})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


@router.post("/game-critic/sessions/{session_id}/recommendations")
async def game_critic_add_recommendation(session_id: str, request: Request):
    """Add an actionable recommendation to a review session."""
    try:
        from sparkai.agent.agent_game_critic import get_game_critic, ReviewDimension
        body = await request.json()
        try:
            dimension = ReviewDimension(body.get("dimension", "fun"))
        except ValueError:
            return JSONResponse(
                {"status": "error", "message": f"invalid dimension: {body.get('dimension')}"},
                status_code=400,
            )
        engine = get_game_critic()
        rec = engine.add_recommendation(
            session_id=session_id,
            dimension=dimension,
            priority=int(body.get("priority", 3)),
            title=body.get("title", ""),
            description=body.get("description", ""),
            linked_finding_ids=body.get("linked_finding_ids"),
            estimated_effort=body.get("estimated_effort", ""),
        )
        if rec is None:
            return JSONResponse(
                {"status": "error", "message": "session not found"},
                status_code=404,
            )
        return JSONResponse({"status": "success", "data": rec.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


