@router.post("/fast-travel/points")
async def fast_travel_register_point(request: Request):
    """Register a new travel point."""
    try:
        from sparkai.engine.engine_fast_travel_system import (
            get_fast_travel_system, PointStatus, TravelMode, CostType, TravelCost,
            TravelRequirement, RequirementType,
        )
        sys = get_fast_travel_system()
        body = await request.json()
        coords = body.get("coordinates", [0.0, 0.0, 0.0])
        if isinstance(coords, list):
            coords = tuple(coords)
        base_cost_data = body.get("base_cost", {})
        base_cost = TravelCost(
            cost_type=CostType(base_cost_data.get("cost_type", "free")),
            amount=float(base_cost_data.get("amount", 0.0)),
            item_id=str(base_cost_data.get("item_id", "")),
        ) if base_cost_data else None
        disc_req_data = body.get("discovery_requirement", {})
        disc_req = TravelRequirement(
            requirement_type=RequirementType(disc_req_data.get("requirement_type", "none")),
            target_id=str(disc_req_data.get("target_id", "")),
            target_value=float(disc_req_data.get("target_value", 0.0)),
        ) if disc_req_data else None
        trav_req_data = body.get("travel_requirement", {})
        trav_req = TravelRequirement(
            requirement_type=RequirementType(trav_req_data.get("requirement_type", "none")),
            target_id=str(trav_req_data.get("target_id", "")),
            target_value=float(trav_req_data.get("target_value", 0.0)),
        ) if trav_req_data else None
        point = sys.register_point(
            name=body.get("name", ""),
            network_id=body.get("network_id", ""),
            coordinates=coords,
            description=body.get("description", ""),
            status=PointStatus(body.get("status", "active")),
            travel_mode=TravelMode(body.get("travel_mode", "instant")),
            base_cost=base_cost,
            discovery_requirement=disc_req,
            travel_requirement=trav_req,
            region=body.get("region", ""),
            tags=body.get("tags", []),
            point_id=body.get("point_id"),
        )
        return JSONResponse({"status": "success", "data": point.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=400)


