@router.post("/fast-travel/connections")
async def fast_travel_connect(request: Request):
    """Create a connection between two travel points."""
    try:
        from sparkai.engine.engine_fast_travel_system import (
            get_fast_travel_system, CostType, TravelCost,
        )
        sys = get_fast_travel_system()
        body = await request.json()
        cost_data = body.get("cost_override")
        cost_override = None
        if cost_data:
            cost_override = TravelCost(
                cost_type=CostType(cost_data.get("cost_type", "free")),
                amount=float(cost_data.get("amount", 0.0)),
                item_id=str(cost_data.get("item_id", "")),
            )
        conn = sys.connect(
            from_point_id=body.get("from_point_id", ""),
            to_point_id=body.get("to_point_id", ""),
            bidirectional=bool(body.get("bidirectional", True)),
            cost_override=cost_override,
            travel_time_seconds=float(body.get("travel_time_seconds", 0.0)),
            enabled=bool(body.get("enabled", True)),
        )
        return JSONResponse({"status": "success", "data": conn.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=400)


