@router.post("/trading-post/listings")
async def trading_post_create_listing(body: dict = Body(...)):
    try:
        from sparkai.engine.engine_trading_post import (
            get_trading_post_system, ListingType, CurrencyType, RarityTier,
        )
        d = get_trading_post_system()
        listing_type = ListingType(body.get("listing_type", "fixed_price"))
        currency = CurrencyType(body.get("currency", "gold"))
        rarity = RarityTier(body.get("rarity", "common"))
        result = d.create_listing(
            seller_id=body.get("seller_id", ""),
            item_id=body.get("item_id", ""),
            item_name=body.get("item_name", ""),
            quantity=int(body.get("quantity", 1)),
            listing_type=listing_type,
            price=float(body.get("price", 0)),
            currency=currency,
            rarity=rarity,
            description=body.get("description", ""),
            expires_in_hours=int(body.get("expires_in_hours", 168)),
            metadata=body.get("metadata"),
        )
        if result is None:
            return JSONResponse({"status": "error", "message": "Validation failed"}, status_code=400)
        return JSONResponse({"status": "success", "data": result.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


