@router.post("/save-encryption/encrypt-save")
async def se_encrypt_save(body: dict = Body(...)):
    try:
        from sparkai.engine.engine_save_encryption import get_save_encryption, EncryptionAlgorithm, KeyDerivation, SaveVersion
        d = get_save_encryption()
        algorithm = EncryptionAlgorithm(body.get("algorithm", "aes_256_gcm"))
        key_derivation = KeyDerivation(body.get("key_derivation", "pbkdf2"))
        version = SaveVersion(body.get("version", "current"))
        result = d.encrypt_save(
            save_id=body.get("save_id", ""),
            player_id=body.get("player_id", ""),
            data=body.get("data", {}),
            algorithm=algorithm,
            key_derivation=key_derivation,
            version=version,
            password=body.get("password", ""),
            expires_in_hours=body.get("expires_in_hours"),
        )
        return JSONResponse({"status": "success", "data": result.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)

