@router.post("/loot-curator/tables/{table_id}/roll")
async def lc_roll_loot(table_id: str, body: Dict[str, Any] = Body(default={})):
    try:
        from sparkai.agent.agent_loot_reward_curator import (
            get_loot_reward_curator, DropPolicy,
        )
        d = get_loot_reward_curator()
        policy_data = body.get("policy", {})
        policy = DropPolicy(
            luck=policy_data.get("luck", 1.0),
            rarity_floor=policy_data.get("rarity_floor", "common"),
            rarity_ceiling=policy_data.get("rarity_ceiling", "mythic"),
            strategy_override=policy_data.get("strategy_override", ""),
            pulse_luck_boost=policy_data.get("pulse_luck_boost", 1.0),
            pulse_rarity_shift=policy_data.get("pulse_rarity_shift", 0.0),
        )
        seed = body.get("seed")
        result = d.roll_loot(table_id, policy=policy, seed=seed)
        return JSONResponse({"status": "success", "data": [r.to_dict() for r in result]})
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)

