@router.post("/rigid-body-3d/bodies")
async def rb3d_register_body(body: Dict[str, Any] = Body(default={})):
    try:
        from sparkai.engine.engine_rigid_body_3d import get_rigid_body_3d
        d = get_rigid_body_3d()
        result = d.register_body(
            body_id=body.get("body_id", ""),
            name=body.get("name", ""),
            description=body.get("description", ""),
            motion_type=body.get("motion_type", "dynamic"),
            mass=body.get("mass", 1.0),
            position=tuple(body.get("position", [0.0, 0.0, 0.0])),
            rotation=tuple(body.get("rotation", [1.0, 0.0, 0.0, 0.0])),
            linear_velocity=tuple(body.get("linear_velocity", [0.0, 0.0, 0.0])),
            angular_velocity=tuple(body.get("angular_velocity", [0.0, 0.0, 0.0])),
            linear_damping=body.get("linear_damping", 0.05),
            angular_damping=body.get("angular_damping", 0.05),
            restitution=body.get("restitution", 0.3),
            friction=body.get("friction", 0.5),
            shape_kind=body.get("shape_kind", "sphere"),
            shape_radius=body.get("shape_radius", 0.5),
            shape_half_extents=tuple(body.get("shape_half_extents", [0.5, 0.5, 0.5])),
            shape_height=body.get("shape_height", 1.0),
            inertia_diagonal=tuple(body.get("inertia_diagonal", [1.0, 1.0, 1.0])),
            scene_id=body.get("scene_id", ""),
            collision_mask=body.get("collision_mask", 0xFFFF),
            collision_group=body.get("collision_group", 0x0001),
            metadata=body.get("metadata", {}),
        )
        return JSONResponse({"status": "success", "data": result.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)

