@router.post("/puzzle-architect/puzzles")
async def pa_register_puzzle(body: Dict[str, Any] = Body(default={})):
    try:
        from sparkai.agent.agent_puzzle_architect import get_puzzle_architect, Puzzle, PuzzleComponent, PuzzleConstraint
        d = get_puzzle_architect()
        components = [PuzzleComponent(**c) if isinstance(c, dict) else c for c in body.get("components", [])]
        constraints = [PuzzleConstraint(**c) if isinstance(c, dict) else c for c in body.get("constraints", [])]
        puzzle = Puzzle(
            puzzle_id=body.get("puzzle_id", ""),
            name=body.get("name", ""),
            description=body.get("description", ""),
            genre=body.get("genre", "logic"),
            difficulty=body.get("difficulty", "normal"),
            theme=body.get("theme", ""),
            components=components,
            constraints=constraints,
            solution_path=body.get("solution_path", []),
            target_solve_time_seconds=body.get("target_solve_time_seconds", 120.0),
            estimated_difficulty=body.get("estimated_difficulty", 0.5),
            status=body.get("status", "draft"),
            seed=body.get("seed", ""),
            tags=body.get("tags", []),
            metadata=body.get("metadata", {}),
        )
        result = d.register_puzzle(puzzle)
        return JSONResponse({"status": "success", "data": result.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)

