@router.post("/cinematographer/shots")
async def cm_register_shot(body: Dict[str, Any] = Body(default={})):
    try:
        from sparkai.agent.agent_cinematographer import get_cinematographer, CinemaShot
        d = get_cinematographer()
        pos_offset = body.get("position_offset", [0.0, 0.0, 0.0])
        look_offset = body.get("look_at_offset", [0.0, 0.0, 0.0])
        shot = CinemaShot(
            shot_id=body.get("shot_id", ""),
            name=body.get("name", ""),
            shot_type=body.get("shot_type", "medium"),
            frame_size=body.get("frame_size", "medium"),
            movement=body.get("movement", "static"),
            mood=body.get("mood", "neutral"),
            target_entity_id=body.get("target_entity_id", ""),
            position_offset=tuple(pos_offset) if isinstance(pos_offset, list) else pos_offset,
            look_at_offset=tuple(look_offset) if isinstance(look_offset, list) else look_offset,
            fov=body.get("fov", 60.0),
            duration_seconds=body.get("duration_seconds", 3.0),
            priority=body.get("priority", 0),
            metadata=body.get("metadata", {}),
        )
        result = d.register_shot(shot)
        return JSONResponse({"status": "success", "data": result.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)

