@router.post("/hitbox-system/hitboxes")
async def hb_register_hitbox(body: Dict[str, Any] = Body(default={})):
    try:
        from sparkai.engine.engine_hitbox_system import get_hitbox_system, HitboxInstance
        d = get_hitbox_system()
        pos = body.get("position", [0.0, 0.0, 0.0])
        dims = body.get("dimensions", [1.0, 1.0, 1.0])
        hb = HitboxInstance(
            instance_id=body.get("instance_id", ""),
            owner_id=body.get("owner_id", ""),
            group=body.get("group", "attack"),
            shape=body.get("shape", "box"),
            position=tuple(pos) if isinstance(pos, list) else pos,
            dimensions=tuple(dims) if isinstance(dims, list) else dims,
            damage_multiplier=body.get("damage_multiplier", 1.0),
            active_frames_start=body.get("active_frames_start", 0),
            active_frames_end=body.get("active_frames_end", 30),
            current_frame=body.get("current_frame", 0),
            limb_name=body.get("limb_name", ""),
            team_id=body.get("team_id", ""),
            team_filter_mode=body.get("team_filter_mode", "enemy_only"),
            status=body.get("status", "inactive"),
            hit_targets=body.get("hit_targets", []),
            metadata=body.get("metadata", {}),
        )
        result = d.register_hitbox(hb)
        return JSONResponse({"status": "success", "data": result.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)

