@router.post("/companion-director/companions", status_code=201)
async def companion_director_register_companion(body: Dict[str, Any] = Body(...)):
    try:
        d = get_companion_director()
        companion = CompanionProfile(
            companion_id=body.get("companion_id", ""),
            name=body.get("name", ""),
            kind=body.get("kind", CompanionKind.PET.value),
            personality=body.get("personality", PersonalityKind.LOYAL.value),
            behavior_mode=body.get("behavior_mode", BehaviorMode.ASSIST.value),
            status=body.get("status", CompanionStatus.ALIVE.value),
            level=_safe_int(body.get("level", 1)),
            experience=_safe_float(body.get("experience", 0.0)),
            affinity=_safe_float(body.get("affinity", 0.0)),
            health=_safe_float(body.get("health", 100.0)),
            max_health=_safe_float(body.get("max_health", 100.0)),
            position=tuple(body.get("position", [0.0, 0.0, 0.0])) if isinstance(body.get("position"), list) else (0.0, 0.0, 0.0),
            target_id=body.get("target_id", ""),
            owner_id=body.get("owner_id", ""),
            stats=CompanionStats(
                strength=_safe_float(body.get("stats", {}).get("strength", 10.0)),
                agility=_safe_float(body.get("stats", {}).get("agility", 10.0)),
                intelligence=_safe_float(body.get("stats", {}).get("intelligence", 10.0)),
                endurance=_safe_float(body.get("stats", {}).get("endurance", 10.0)),
                loyalty=_safe_float(body.get("stats", {}).get("loyalty", 10.0)),
            ) if isinstance(body.get("stats"), dict) else CompanionStats(),
            metadata=body.get("metadata", {}),
        )
        abilities_data = body.get("abilities", [])
        if isinstance(abilities_data, list):
            for ab_data in abilities_data:
                if isinstance(ab_data, dict):
                    companion.abilities.append(CompanionAbility(
                        ability_id=ab_data.get("ability_id", ""),
                        name=ab_data.get("name", ""),
                        kind=ab_data.get("kind", AbilityKind.MELEE.value),
                        cooldown=_safe_float(ab_data.get("cooldown", 5.0)),
                        damage=_safe_float(ab_data.get("damage", 0.0)),
                        heal=_safe_float(ab_data.get("heal", 0.0)),
                        duration=_safe_float(ab_data.get("duration", 0.0)),
                        range=_safe_float(ab_data.get("range", 5.0)),
                        description=ab_data.get("description", ""),
                    ))
        result = d.register_companion(companion)
        return JSONResponse({"status": "success", "data": result.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)

