        value = _safe_float(body.get("value", 0.0))
        pos = body.get("world_position", [0.0, 0.0])
        world_position = (pos[0], pos[1]) if isinstance(pos, list) and len(pos) >= 2 else (0.0, 0.0)
        target_id = body.get("target_id", "")
        custom_text = body.get("custom_text", "")
        color_override = body.get("color_override", "")
