        metadata = body.get("metadata", {})
        result = d.spawn_text(kind, value, world_position, target_id=target_id, custom_text=custom_text, color_override=color_override, priority=priority, metadata=metadata)
        return JSONResponse({"status": "success", "data": result.to_dict()}, status_code=201)
