# ===========================================================================
# Round 22 - Vehicle Physics System Routes
# ===========================================================================

from sparkai.engine.engine_vehicle_physics import (
    VehicleKind,
    DriveType,
    WheelPosition,
    SurfaceGrip,
    VehicleStatus,
    DamageZone,
    VehicleEventKind,
    WheelSpec,
    EngineSpec,
    VehicleConfig,
    VehicleState,
    DamageRecord,
    VehicleProfile,
    get_vehicle_physics,
)


def _r22_float(value: Any, default: float = 0.0) -> float:
    try:
        if value is None:
            return default
        return float(value)
    except (TypeError, ValueError):
        return default


def _r22_int(value: Any, default: int = 0) -> int:
    try:
        if value is None:
            return default
        return int(value)
    except (TypeError, ValueError):
        return default


def _r22_tuple3(value: Any, default: tuple = (0.0, 0.0, 0.0)) -> tuple:
    if isinstance(value, list) and len(value) >= 3:
        return (float(value[0]), float(value[1]), float(value[2]))
    if isinstance(value, tuple) and len(value) >= 3:
        return (float(value[0]), float(value[1]), float(value[2]))
    return default


def _r22_build_wheels(body: Dict[str, Any]) -> List[WheelSpec]:
    wheels_data = body.get("wheels", [])
    if not isinstance(wheels_data, list):
        return []
    wheels: List[WheelSpec] = []
    for wd in wheels_data:
        if not isinstance(wd, dict):
            continue
        wheels.append(WheelSpec(
            wheel_id=wd.get("wheel_id", ""),
            position=wd.get("position", WheelPosition.FRONT_LEFT.value),
            radius=_r22_float(wd.get("radius", 0.34)),
            width=_r22_float(wd.get("width", 0.25)),
            mass=_r22_float(wd.get("mass", 25.0)),
            steer_angle=_r22_float(wd.get("steer_angle", 0.0)),
            drive=bool(wd.get("drive", True)),
            brake=bool(wd.get("brake", True)),
            handbrake=bool(wd.get("handbrake", False)),
            suspension_rest_length=_r22_float(wd.get("suspension_rest_length", 0.35)),
            spring_stiffness=_r22_float(wd.get("spring_stiffness", 35000.0)),
            damper_compression=_r22_float(wd.get("damper_compression", 4500.0)),
            damper_rebound=_r22_float(wd.get("damper_rebound", 6000.0)),
            max_steer=_r22_float(wd.get("max_steer", 35.0)),
            lateral_grip=_r22_float(wd.get("lateral_grip", 1.0)),
            longitudinal_grip=_r22_float(wd.get("longitudinal_grip", 1.0)),
            metadata=wd.get("metadata", {}),
        ))
    return wheels


def _r22_build_engine(body: Dict[str, Any]) -> EngineSpec:
    engine_body = body.get("engine", {})
    if not isinstance(engine_body, dict):
        return EngineSpec()
    torque_curve = engine_body.get("torque_curve", [])
    if isinstance(torque_curve, list):
        curve = []
        for point in torque_curve:
            if isinstance(point, list) and len(point) >= 2:
                curve.append((float(point[0]), float(point[1])))
        torque_curve = curve
    gear_ratios = engine_body.get("gear_ratios", [3.5, 2.1, 1.4, 1.0, 0.8, 0.65])
    if not isinstance(gear_ratios, list):
        gear_ratios = [3.5, 2.1, 1.4, 1.0, 0.8, 0.65]
    return EngineSpec(
        max_torque=_r22_float(engine_body.get("max_torque", 400.0)),
        max_power=_r22_float(engine_body.get("max_power", 250000.0)),
        rpm_idle=_r22_float(engine_body.get("rpm_idle", 800.0)),
        rpm_max=_r22_float(engine_body.get("rpm_max", 7000.0)),
        rpm_redline=_r22_float(engine_body.get("rpm_redline", 7500.0)),
        torque_curve=torque_curve,
        fuel_consumption_rate=_r22_float(engine_body.get("fuel_consumption_rate", 0.08)),
        gear_ratios=[float(g) for g in gear_ratios],
        reverse_ratio=_r22_float(engine_body.get("reverse_ratio", 3.2)),
        differential_ratio=_r22_float(engine_body.get("differential_ratio", 3.7)),
        efficiency=_r22_float(engine_body.get("efficiency", 0.92)),
    )


def _r22_build_vehicle_config(body: Dict[str, Any]) -> VehicleConfig:
    cfg_body = body.get("config", {})
    if not isinstance(cfg_body, dict):
        return VehicleConfig()
    return VehicleConfig(
        max_vehicles=_r22_int(cfg_body.get("max_vehicles", 500)),
        max_wheels_per_vehicle=_r22_int(cfg_body.get("max_wheels_per_vehicle", 8)),
        gravity=_r22_float(cfg_body.get("gravity", 9.81)),
        air_density=_r22_float(cfg_body.get("air_density", 1.225)),
        drag_coefficient=_r22_float(cfg_body.get("drag_coefficient", 0.32)),
        frontal_area=_r22_float(cfg_body.get("frontal_area", 2.2)),
        downforce_coefficient=_r22_float(cfg_body.get("downforce_coefficient", 0.0)),
        brake_bias=_r22_float(cfg_body.get("brake_bias", 0.55)),
        abs_enabled=bool(cfg_body.get("abs_enabled", True)),
        traction_control=bool(cfg_body.get("traction_control", True)),
        stability_control=bool(cfg_body.get("stability_control", True)),
        handbrake_force=_r22_float(cfg_body.get("handbrake_force", 8000.0)),
        roll_resistance=_r22_float(cfg_body.get("roll_resistance", 0.015)),
        fuel_enabled=bool(cfg_body.get("fuel_enabled", True)),
        fuel_capacity=_r22_float(cfg_body.get("fuel_capacity", 60.0)),
        damage_enabled=bool(cfg_body.get("damage_enabled", True)),
        auto_transmission=bool(cfg_body.get("auto_transmission", True)),
        shift_up_rpm=_r22_float(cfg_body.get("shift_up_rpm", 6000.0)),
        shift_down_rpm=_r22_float(cfg_body.get("shift_down_rpm", 2500.0)),
    )


@router.post("/vehicle-physics/vehicles")
async def vp_register_vehicle(body: Dict[str, Any] = Body(default={})):
    try:
        d = get_vehicle_physics()
        vehicle = VehicleProfile(
            vehicle_id=body.get("vehicle_id", ""),
            name=body.get("name", ""),
            kind=body.get("kind", VehicleKind.CAR.value),
            drive_type=body.get("drive_type", DriveType.RWD.value),
            mass=_r22_float(body.get("mass", 1500.0)),
            center_of_mass=_r22_tuple3(body.get("center_of_mass"), (0.0, -0.4, 0.0)),
            wheelbase=_r22_float(body.get("wheelbase", 2.7)),
            track_width=_r22_float(body.get("track_width", 1.6)),
            length=_r22_float(body.get("length", 4.5)),
            width=_r22_float(body.get("width", 1.85)),
            height=_r22_float(body.get("height", 1.4)),
            wheels=_r22_build_wheels(body),
            engine=_r22_build_engine(body),
            config=_r22_build_vehicle_config(body),
            metadata=body.get("metadata", {}),
        )
        result = d.register_vehicle(vehicle)
        return JSONResponse({"status": "success", "data": result.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


