@router.post("/cover-system/covers")
async def cs_register_cover(body: Dict[str, Any] = Body(default={})):
    try:
        d = get_cover_system()
        pos = body.get("position", [0.0, 0.0, 0.0])
        cover = CoverPoint(
            cover_id=body.get("cover_id", ""),
            position=_r22_tuple3(pos),
            quality=body.get("quality", CoverQuality.FULL.value),
            stance=body.get("stance", CoverStance.CROUCH.value),
            direction=body.get("direction", CoverDirection.NORTH.value),
            material=body.get("material", CoverMaterial.CONCRETE.value),
            max_occupants=_r22_int(body.get("max_occupants", 1)),
            current_occupants=body.get("current_occupants", []),
            health=_r22_float(body.get("health", 100.0)),
            max_health=_r22_float(body.get("max_health", 100.0)),
            height=_r22_float(body.get("height", 1.0)),
            width=_r22_float(body.get("width", 1.5)),
            status=body.get("status", CoverStatus.AVAILABLE.value),
            reserved_by=body.get("reserved_by"),
            reserved_until=_r22_float(body.get("reserved_until", 0.0)),
            metadata=body.get("metadata", {}),
        )
        result = d.register_cover(cover)
        return JSONResponse({"status": "success", "data": result.to_dict()}, status_code=201)
    except Exception as e:
        return JSONResponse({"status": "error", "message": str(e)}, status_code=500)


