def _r23_float(v, d=0.0):
    try:
        return float(v) if v is not None else d
    except (TypeError, ValueError):
        return d


def _r23_int(v, d=0):
    try:
        return int(v) if v is not None else d
    except (TypeError, ValueError):
        return d


def _r23_tuple3(v, d=(0.0, 0.0, 0.0)):
    if isinstance(v, (list, tuple)) and len(v) >= 3:
        return (float(v[0]), float(v[1]), float(v[2]))
    return d


def _r23_build_sky_stops(stops_data):
    stops = []
    if not isinstance(stops_data, list):
        return stops
    for s in stops_data:
        if not isinstance(s, dict):
            continue
        stops.append(SkyColorStop(
            time=_r23_float(s.get("time"), 0.0),
            zenith_color=_r23_tuple3(s.get("zenith_color"), (0.1, 0.2, 0.5)),
            horizon_color=_r23_tuple3(s.get("horizon_color"), (0.5, 0.6, 0.8)),
            sun_color=_r23_tuple3(s.get("sun_color"), (1.0, 0.9, 0.7)),
            sun_glow=_r23_float(s.get("sun_glow"), 0.5),
        ))
    return stops


def _r23_build_sky_preset(data):
    return SkyPreset(
        preset_id=str(data.get("preset_id", "")),
        name=str(data.get("name", "")),
        description=str(data.get("description", "")),
        color_stops=_r23_build_sky_stops(data.get("color_stops", [])),
    )


def _r23_build_daynight_config(data):
    return DayNightConfig(
        day_length_seconds=_r23_float(data.get("day_length_seconds"), 120.0),
        time_scale=_r23_float(data.get("time_scale"), 1.0),
        latitude=_r23_float(data.get("latitude"), 35.0),
        start_time=_r23_float(data.get("start_time"), 8.0),
        axial_tilt=_r23_float(data.get("axial_tilt"), 23.5),
        moon_cycle_days=_r23_float(data.get("moon_cycle_days"), 29.5),
        auto_advance=bool(data.get("auto_advance", True)),
        star_intensity=_r23_float(data.get("star_intensity"), 0.8),
        cloud_shadow_factor=_r23_float(data.get("cloud_shadow_factor"), 0.3),
    )


def _r23_build_field_shape(data):
    return FieldShape(
        kind=str(data.get("kind", "box")),
        center=_r23_tuple3(data.get("center")),
        size=_r23_tuple3(data.get("size"), (10.0, 10.0, 10.0)),
        radius=_r23_float(data.get("radius"), 5.0),
        height=_r23_float(data.get("height"), 10.0),
        rotation_yaw=_r23_float(data.get("rotation_yaw")),
        rotation_pitch=_r23_float(data.get("rotation_pitch")),
        rotation_roll=_r23_float(data.get("rotation_roll")),
    )


def _r23_build_gravity_field(data):
    return GravityField(
        field_id=str(data.get("field_id", "")),
        name=str(data.get("name", "")),
        kind=str(data.get("kind", "box")),
        mode=str(data.get("mode", "absolute")),
        priority=str(data.get("priority", "normal")),
        shape=_r23_build_field_shape(data.get("shape", {})),
        gravity_vector=_r23_tuple3(data.get("gravity_vector"), (0.0, -9.81, 0.0)),
        magnitude=_r23_float(data.get("magnitude"), 9.81),
        direction=_r23_tuple3(data.get("direction"), (0.0, -1.0, 0.0)),
        falloff=str(data.get("falloff", "linear")),
        falloff_start=_r23_float(data.get("falloff_start")),
        falloff_end=_r23_float(data.get("falloff_end"), 1.0),
        enabled=bool(data.get("enabled", True)),
        blend_weight=_r23_float(data.get("blend_weight"), 1.0),
        attract_point=_r23_tuple3(data.get("attract_point")),
        attract_strength=_r23_float(data.get("attract_strength"), 9.81),
        min_distance=_r23_float(data.get("min_distance"), 0.1),
        max_distance=_r23_float(data.get("max_distance"), 100.0),
        metadata=data.get("metadata", {}),
    )


def _r23_build_gravity_well(data):
    return GravityWell(
        well_id=str(data.get("well_id", "")),
        name=str(data.get("name", "")),
        position=_r23_tuple3(data.get("position")),
        mass=_r23_float(data.get("mass"), 5.972e24),
        gravitational_constant=_r23_float(data.get("gravitational_constant"), 6.674e-11),
        repel=bool(data.get("repel", False)),
        enabled=bool(data.get("enabled", True)),
        inner_radius=_r23_float(data.get("inner_radius"), 1.0),
        outer_radius=_r23_float(data.get("outer_radius"), 100.0),
        falloff=str(data.get("falloff", "inverse_square")),
        max_acceleration=_r23_float(data.get("max_acceleration"), 30.0),
        metadata=data.get("metadata", {}),
    )


def _r23_build_gravity_config(data):
    return GravityConfig(
        default_gravity=_r23_tuple3(data.get("default_gravity"), (0.0, -9.81, 0.0)),
        default_magnitude=_r23_float(data.get("default_magnitude"), 9.81),
        max_fields=_r23_int(data.get("max_fields"), 500),
        max_wells=_r23_int(data.get("max_wells"), 100),
        max_tracked_bodies=_r23_int(data.get("max_tracked_bodies"), 1000),
        blend_strategy=str(data.get("blend_strategy", "weighted_average")),
        zero_g_threshold=_r23_float(data.get("zero_g_threshold"), 0.05),
        enable_wells=bool(data.get("enable_wells", True)),
        enable_field_blending=bool(data.get("enable_field_blending", True)),
        body_tracking_enabled=bool(data.get("body_tracking_enabled", True)),
        global_field_id=str(data.get("global_field_id", "fld_global_default")),
    )


def _r23_build_keyframes(data):
    kfs = []
    if not isinstance(data, list):
        return kfs
    for k in data:
        if not isinstance(k, dict):
            continue
        kfs.append(IntensityKeyframe(
            time=_r23_float(k.get("time")),
            intensity=_r23_float(k.get("intensity"), 0.5),
            label=str(k.get("label", "")),
        ))
    return kfs


def _r23_build_pacing_curve(data):
    return PacingCurve(
        curve_id=str(data.get("curve_id", "")),
        name=str(data.get("name", "")),
        duration=_r23_float(data.get("duration"), 300.0),
        loop=bool(data.get("loop", True)),
        keyframes=_r23_build_keyframes(data.get("keyframes", [])),
        enabled=bool(data.get("enabled", True)),
        metadata=data.get("metadata", {}),
    )


def _r23_build_telemetry(data):
    return TelemetrySample(
        sample_id=str(data.get("sample_id", "")),
        kind=str(data.get("kind", "custom")),
        timestamp=_r23_float(data.get("timestamp")),
        player_id=str(data.get("player_id", "")),
        intensity_delta=_r23_float(data.get("intensity_delta")),
        value=_r23_float(data.get("value")),
        position=_r23_tuple3(data.get("position")),
        details=data.get("details", {}),
    )


def _r23_build_directive(data):
    return PacingDirective(
        directive_id=str(data.get("directive_id", "")),
        kind=str(data.get("kind", "adjust_pacing")),
        timestamp=_r23_float(data.get("timestamp")),
        intensity_target=_r23_float(data.get("intensity_target"), 0.5),
        phase=str(data.get("phase", "buildup")),
        parameters=data.get("parameters", {}),
        priority=_r23_int(data.get("priority"), 5),
        consumed=bool(data.get("consumed", False)),
        consumed_by=str(data.get("consumed_by", "")),
        expires_at=_r23_float(data.get("expires_at")),
    )


def _r23_build_engagement(data):
    return EngagementState(
        level=str(data.get("level", "engaged")),
        intensity=_r23_float(data.get("intensity"), 0.5),
        flow_score=_r23_float(data.get("flow_score"), 0.5),
        challenge=_r23_float(data.get("challenge"), 0.5),
        skill=_r23_float(data.get("skill"), 0.5),
        fatigue=_r23_float(data.get("fatigue")),
        boredom=_r23_float(data.get("boredom")),
        frustration=_r23_float(data.get("frustration")),
        last_kill_time=_r23_float(data.get("last_kill_time")),
        last_death_time=_r23_float(data.get("last_death_time")),
        kill_streak=_r23_int(data.get("kill_streak")),
        death_streak=_r23_int(data.get("death_streak")),
    )


def _r23_build_pacing_config(data):
    return PacingConfig(
        target_flow_score=_r23_float(data.get("target_flow_score"), 0.7),
        intensity_smoothing=_r23_float(data.get("intensity_smoothing"), 0.15),
        fatigue_decay_per_tick=_r23_float(data.get("fatigue_decay_per_tick"), 0.005),
        fatigue_gain_per_kill=_r23_float(data.get("fatigue_gain_per_kill"), 0.02),
        fatigue_gain_per_death=_r23_float(data.get("fatigue_gain_per_death"), 0.04),
        boredom_gain_per_idle_tick=_r23_float(data.get("boredom_gain_per_idle_tick"), 0.01),
        boredom_decay_per_event=_r23_float(data.get("boredom_decay_per_event"), 0.05),
        frustration_gain_per_fail=_r23_float(data.get("frustration_gain_per_fail"), 0.03),
        frustration_decay_per_tick=_r23_float(data.get("frustration_decay_per_tick"), 0.008),
        phase_change_threshold=_r23_float(data.get("phase_change_threshold"), 0.25),
        climax_intensity_threshold=_r23_float(data.get("climax_intensity_threshold"), 0.85),
        lull_intensity_threshold=_r23_float(data.get("lull_intensity_threshold"), 0.25),
        rest_duration=_r23_float(data.get("rest_duration"), 30.0),
        max_directives=_r23_int(data.get("max_directives"), 200),
        auto_issue_directives=bool(data.get("auto_issue_directives", True)),
        default_curve_id=str(data.get("default_curve_id", "curve_default_arc")),
    )


