# ---------------------------------------------------------------------------
# Round 24 Helper Functions
# ---------------------------------------------------------------------------

def _r24_float(v, d=0.0):
    try:
        return float(v) if v is not None else d
    except (TypeError, ValueError):
        return d


def _r24_int(v, d=0):
    try:
        return int(v) if v is not None else d
    except (TypeError, ValueError):
        return d


def _r24_tuple3(v, d=(0.0, 0.0, 0.0)):
    if isinstance(v, (list, tuple)) and len(v) >= 3:
        return (float(v[0]), float(v[1]), float(v[2]))
    return d


def _r24_str_list(v):
    if isinstance(v, list):
        return [str(x) for x in v]
    return []


def _r24_build_volume_geometry(data):
    if not isinstance(data, dict):
        data = {}
    return VolumeGeometry(
        shape=str(data.get("shape", "box")),
        center=_r24_tuple3(data.get("center")),
        size=_r24_tuple3(data.get("size"), (10.0, 10.0, 10.0)),
        radius=_r24_float(data.get("radius"), 5.0),
        height=_r24_float(data.get("height"), 10.0),
        rotation_yaw=_r24_float(data.get("rotation_yaw"), 0.0),
    )


def _r24_build_trigger_condition(data):
    if not isinstance(data, dict):
        data = {}
    return TriggerCondition(
        condition_id=str(data.get("condition_id", "")),
        required_tag=str(data.get("required_tag", "")),
        required_property=str(data.get("required_property", "")),
        required_value=_r24_float(data.get("required_value"), 0.0),
        min_entity_count=_r24_int(data.get("min_entity_count"), 0),
        max_entity_count=_r24_int(data.get("max_entity_count"), 0),
        require_all_tags=bool(data.get("require_all_tags", False)),
        invert=bool(data.get("invert", False)),
    )


def _r24_build_trigger_volume(data):
    return TriggerVolume(
        volume_id=str(data.get("volume_id", "")),
        name=str(data.get("name", "")),
        shape=str(data.get("shape", "box")),
        geometry=_r24_build_volume_geometry(data.get("geometry", {})),
        mode=str(data.get("mode", "oneshot")),
        state=str(data.get("state", "active")),
        enabled=bool(data.get("enabled", True)),
        cooldown_seconds=_r24_float(data.get("cooldown_seconds"), 1.0),
        pulse_interval=_r24_float(data.get("pulse_interval"), 1.0),
        max_activations=_r24_int(data.get("max_activations"), 0),
        activation_count=_r24_int(data.get("activation_count"), 0),
        last_fire_time=_r24_float(data.get("last_fire_time"), 0.0),
        last_pulse_time=_r24_float(data.get("last_pulse_time"), 0.0),
        filter_tags=_r24_str_list(data.get("filter_tags")),
        filter_entity_ids=_r24_str_list(data.get("filter_entity_ids")),
        exclude_entity_ids=_r24_str_list(data.get("exclude_entity_ids")),
        condition=_r24_build_trigger_condition(data.get("condition", {})),
        payload=data.get("payload", {}) if isinstance(data.get("payload"), dict) else {},
        metadata=data.get("metadata", {}) if isinstance(data.get("metadata"), dict) else {},
        created_at=_r24_float(data.get("created_at"), 0.0),
        updated_at=_r24_float(data.get("updated_at"), 0.0),
    )


def _r24_build_trigger_config(data):
    return TriggerConfig(
        max_volumes=_r24_int(data.get("max_volumes"), 500),
        max_occupants_per_volume=_r24_int(data.get("max_occupants_per_volume"), 200),
        default_cooldown=_r24_float(data.get("default_cooldown"), 1.0),
        default_pulse_interval=_r24_float(data.get("default_pulse_interval"), 1.0),
        auto_expire=bool(data.get("auto_expire", True)),
        expire_after_seconds=_r24_float(data.get("expire_after_seconds"), 30.0),
        enable_conditions=bool(data.get("enable_conditions", True)),
        tick_rate_hz=_r24_float(data.get("tick_rate_hz"), 60.0),
    )


def _r24_build_ragdoll_config(data):
    return RagdollConfig(
        max_ragdolls=_r24_int(data.get("max_ragdolls"), 200),
        max_bones_per_ragdoll=_r24_int(data.get("max_bones_per_ragdoll"), 32),
        gravity=_r24_tuple3(data.get("gravity"), (0.0, -9.81, 0.0)),
        air_drag=_r24_float(data.get("air_drag"), 0.02),
        ground_friction=_r24_float(data.get("ground_friction"), 0.6),
        restitution=_r24_float(data.get("restitution"), 0.2),
        settle_threshold=_r24_float(data.get("settle_threshold"), 0.3),
        settle_time=_r24_float(data.get("settle_time"), 2.0),
        auto_settle=bool(data.get("auto_settle", True)),
        auto_remove_after_settle=bool(data.get("auto_remove_after_settle", False)),
        auto_remove_delay=_r24_float(data.get("auto_remove_delay"), 10.0),
        bone_solver_iterations=_r24_int(data.get("bone_solver_iterations"), 4),
    )


def _r24_build_material_entry(data):
    if not isinstance(data, dict):
        data = {}
    return MaterialEntry(
        item_id=str(data.get("item_id", "")),
        quantity=_r24_int(data.get("quantity"), 1),
        metadata=data.get("metadata", {}) if isinstance(data.get("metadata"), dict) else {},
    )


def _r24_build_output_entry(data):
    if not isinstance(data, dict):
        data = {}
    return OutputEntry(
        item_id=str(data.get("item_id", "")),
        quantity=_r24_int(data.get("quantity"), 1),
        quality_min=_r24_float(data.get("quality_min"), 0.0),
        quality_max=_r24_float(data.get("quality_max"), 1.0),
        chance=_r24_float(data.get("chance"), 1.0),
        metadata=data.get("metadata", {}) if isinstance(data.get("metadata"), dict) else {},
    )


def _r24_build_recipe(data):
    inputs_data = data.get("inputs", [])
    outputs_data = data.get("outputs", [])
    inputs = [_r24_build_material_entry(x) for x in inputs_data] if isinstance(inputs_data, list) else []
    outputs = [_r24_build_output_entry(x) for x in outputs_data] if isinstance(outputs_data, list) else []
    return CraftRecipe(
        recipe_id=str(data.get("recipe_id", "")),
        name=str(data.get("name", "")),
        category=str(data.get("category", "misc")),
        description=str(data.get("description", "")),
        inputs=inputs,
        outputs=outputs,
        required_station=str(data.get("required_station", "")),
        required_skill=str(data.get("required_skill", "")),
        required_skill_level=_r24_int(data.get("required_skill_level"), 0),
        craft_time=_r24_float(data.get("craft_time"), 1.0),
        success_rate=_r24_float(data.get("success_rate"), 0.9),
        unlocked=bool(data.get("unlocked", True)),
        discoverable=bool(data.get("discoverable", False)),
        discovery_hint=str(data.get("discovery_hint", "")),
        batch_size=_r24_int(data.get("batch_size"), 1),
        metadata=data.get("metadata", {}) if isinstance(data.get("metadata"), dict) else {},
        created_at=_r24_float(data.get("created_at"), 0.0),
    )


def _r24_build_station(data):
    return CraftStation(
        station_id=str(data.get("station_id", "")),
        name=str(data.get("name", "")),
        station_type=str(data.get("station_type", "workbench")),
        position=_r24_tuple3(data.get("position")),
        enabled=bool(data.get("enabled", True)),
        efficiency=_r24_float(data.get("efficiency"), 1.0),
        bonus_success_rate=_r24_float(data.get("bonus_success_rate"), 0.0),
        bonus_quality=_r24_float(data.get("bonus_quality"), 0.0),
        skill_bonus=_r24_int(data.get("skill_bonus"), 0),
        metadata=data.get("metadata", {}) if isinstance(data.get("metadata"), dict) else {},
        created_at=_r24_float(data.get("created_at"), 0.0),
    )


def _r24_build_craft_config(data):
    return CraftConfig(
        max_recipes=_r24_int(data.get("max_recipes"), 500),
        max_stations=_r24_int(data.get("max_stations"), 200),
        max_concurrent_crafts=_r24_int(data.get("max_concurrent_crafts"), 100),
        default_success_rate=_r24_float(data.get("default_success_rate"), 0.9),
        skill_check_enabled=bool(data.get("skill_check_enabled", True)),
        quality_variance=_r24_float(data.get("quality_variance"), 0.1),
        auto_complete=bool(data.get("auto_complete", True)),
        tick_rate_hz=_r24_float(data.get("tick_rate_hz"), 10.0),
    )


